  }
}

export async function sendSignupVerificationEmail(
  admin: SupabaseClient,
  rawEmail: string,
): Promise<{ ok: boolean; message: string; alreadyVerified?: boolean }> {
  const email = rawEmail.trim().toLowerCase();
  if (!email || !email.includes('@')) {
    return { ok: false, message: 'Enter a valid email address.' };
  }

  const { data: verified } = await admin.rpc('is_signup_email_verified', { p_email: email });
  if (verified) {
    return { ok: true, message: 'Email already verified. You can sign in.', alreadyVerified: true };
  }

  const { data: existing } = await admin
    .from('user_signup_email_verifications')
    .select('email, resent_count, last_sent_at, verified_at')
    .eq('email', email)
    .maybeSingle();

  if (existing?.verified_at) {
    return { ok: true, message: 'Email already verified. You can sign in.', alreadyVerified: true };
  }

  const now = Date.now();
  if (existing?.last_sent_at) {
    const lastSent = new Date(String(existing.last_sent_at)).getTime();
    if (now - lastSent < RESEND_COOLDOWN_MS) {
      return {
        ok: true,
        message: 'Verification email already sent. Check your inbox (and spam), or wait a few minutes to resend.',
      };
    }
    if (Number(existing.resent_count ?? 0) >= MAX_RESENDS_PER_DAY) {
      return { ok: false, message: 'Too many verification emails today. Try again tomorrow or contact support.' };
    }
  }

  const token = crypto.randomUUID().replace(/-/g, '') + crypto.randomUUID().replace(/-/g, '');
  const tokenHash = await hashToken(token);
  const expiresAt = new Date(now + TOKEN_TTL_HOURS * 60 * 60 * 1000).toISOString();
  const verifyUrl = `${appOrigin()}/verify-email?token=${encodeURIComponent(token)}`;
  const loginUrl = `${appOrigin()}/login`;

  const { error: upsertErr } = await admin.from('user_signup_email_verifications').upsert({
    email,
    token_hash: tokenHash,
    expires_at: expiresAt,
    verified_at: null,
    resent_count: Number(existing?.resent_count ?? 0) + (existing ? 1 : 0),
    last_sent_at: new Date().toISOString(),
  });
  if (upsertErr) {
    return { ok: false, message: 'Could not start verification. Try again.' };
  }

  const body = [
    'Welcome to RedFace Pay!',
    '',
    'Verify your email to activate your account:',
    verifyUrl,
    '',
    `This link expires in ${TOKEN_TTL_HOURS} hours.`,
    '',
    `After verifying, sign in here: ${loginUrl}`,
    '',
    'If you did not create a RedFace account, you can ignore this email.',
  ].join('\n');

  await admin.rpc('enqueue_platform_notification', {
    p_channel: 'email',
    p_recipient: email,
    p_event_type: 'signup_verification',
    p_body: body,
    p_payload: { verify_url: verifyUrl, login_url: loginUrl },
    p_subject: 'Verify your RedFace Pay email',
    p_reference: `signup_verify:${email}`,
  }).then(() => {}, () => {});

  void nudgeNotificationService();

  return {
    ok: true,
    message: 'Verification email sent. Check your inbox, then sign in after you verify.',
  };
}

/** Fare authorization — Takasit / mobility authorize-on-board, capture-on-complete. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import {
  capturePaystackPreauthorization,
  releasePaystackPreauthorization,
} from './paystackApi.ts';

export type FareAuthRow = {
  id: string;
  merchant_id: string;
  reservation_id: string | null;
  amount_zar: number;
  captured_amount_zar: number | null;
  currency: string;
  label: string | null;
  status: string;
  payment_method: string | null;
  paystack_reference: string | null;
  paystack_preauth_reference: string | null;
  paystack_authorization_code: string | null;
  buyer_email: string | null;
  capture_reference: string | null;
  transaction_id: string | null;
  metadata: Record<string, unknown>;
};

export function buildFarePreauthReference(authorizationId: string): string {
  return `RFPR-${authorizationId.replace(/-/g, '').slice(0, 24)}`;
}

export async function createFareAuthorization(
  admin: SupabaseClient,
  opts: {
    merchantId: string;
    amountZar: number;
    currency?: string;
    label?: string;
    reservationId?: string;
    paymentMethod?: string;
    buyerEmail?: string;
    status?: string;
    paystackPreauthReference?: string;
    metadata?: Record<string, unknown>;
  },
): Promise<{ ok: true; row: FareAuthRow } | { ok: false; message: string }> {
  const { data: merchant } = await admin
    .from('merchants')
    .select('id, status')
    .eq('id', opts.merchantId)
    .maybeSingle();

  if (!merchant || merchant.status !== 'approved') {
    return { ok: false, message: 'Merchant not found or not approved' };
  }

  const amount = Number(opts.amountZar);
  if (!Number.isFinite(amount) || amount <= 0) {
    return { ok: false, message: 'amount must be greater than zero' };
  }

  const { data, error } = await admin
    .from('fare_authorizations')
    .insert({
      merchant_id: opts.merchantId,
      reservation_id: opts.reservationId?.trim() || null,
      amount_zar: amount,
      currency: opts.currency ?? 'ZAR',
      label: opts.label?.trim() || null,
      payment_method: opts.paymentMethod ?? 'redface',
      buyer_email: opts.buyerEmail?.trim().toLowerCase() || null,
      status: opts.status ?? 'authorized',
      paystack_preauth_reference: opts.paystackPreauthReference ?? null,
      metadata: {
        source: 'takasit',
        ...(opts.metadata ?? {}),
      },
    })
    .select()
    .single();

  if (error || !data) {
    return { ok: false, message: error?.message ?? 'Could not create authorization' };
  }

  return { ok: true, row: data as FareAuthRow };
}

export async function markFarePreauthReserved(
  admin: SupabaseClient,
  reference: string,
  patch: {
    authorizationCode?: string | null;
    buyerEmail?: string | null;
    fareAuthorizationId?: string | null;
  } = {},
): Promise<FareAuthRow | null> {
  const now = new Date().toISOString();
  const update = {
    status: 'authorized',
    paystack_preauth_reference: reference,
    paystack_reference: reference,
    paystack_authorization_code: patch.authorizationCode ?? null,
    buyer_email: patch.buyerEmail ?? null,
    authorized_at: now,
    updated_at: now,
  };

  const { data } = await admin
    .from('fare_authorizations')
    .update(update)
    .eq('paystack_preauth_reference', reference)
    .in('status', ['pending_preauth', 'authorized'])
    .select()
    .maybeSingle();

  if (data) return data as FareAuthRow;

  if (patch.fareAuthorizationId) {
    const { data: byId } = await admin
      .from('fare_authorizations')
      .update(update)
      .eq('id', patch.fareAuthorizationId)
      .in('status', ['pending_preauth', 'authorized'])
      .select()
      .maybeSingle();
    return (byId as FareAuthRow) ?? null;
  }

  return null;
}

export async function captureFareAuthorization(
  admin: SupabaseClient,
  opts: {
    authorizationId: string;
    merchantId?: string;
    amountZar?: number;
    recordOnly?: boolean;
    paystackSecret?: string;
    platformFee?: number;
  },
): Promise<{ ok: true; row: FareAuthRow } | { ok: false; message: string }> {
  let q = admin.from('fare_authorizations').select('*').eq('id', opts.authorizationId);
  if (opts.merchantId) q = q.eq('merchant_id', opts.merchantId);
  const { data: row, error } = await q.maybeSingle();

  if (error || !row) {
    return { ok: false, message: 'Authorization not found' };
  }

  const auth = row as FareAuthRow;
  if (auth.status === 'captured') {
    return { ok: true, row: auth };
  }
  if (!['authorized', 'capture_initiated'].includes(auth.status)) {
    return { ok: false, message: `Authorization is ${auth.status}` };
  }

  const captureAmount = opts.amountZar ?? Number(auth.amount_zar);
  const now = new Date().toISOString();

  if (opts.recordOnly || auth.payment_method === 'cash' || !auth.paystack_preauth_reference) {
    const { data: updated, error: upErr } = await admin
      .from('fare_authorizations')
      .update({
        status: 'captured',
        captured_amount_zar: captureAmount,
        captured_at: now,
        updated_at: now,
      })
      .eq('id', auth.id)
      .select()
      .single();
    if (upErr || !updated) {
      return { ok: false, message: upErr?.message ?? 'Capture failed' };
    }
    return { ok: true, row: updated as FareAuthRow };
  }

  if (!opts.paystackSecret) {
    return { ok: false, message: 'Paystack is not configured for capture.' };
  }

  const captureRef = auth.capture_reference ?? `takasit-cap-${auth.id}`;
  await admin.from('fare_authorizations').update({
    status: 'capture_initiated',
    captured_amount_zar: captureAmount,
    capture_reference: captureRef,
    updated_at: now,
  }).eq('id', auth.id);

  const ps = await capturePaystackPreauthorization(opts.paystackSecret, {
    reference: auth.paystack_preauth_reference,
    amountMajor: captureAmount,
    currency: auth.currency,
  });

  if (!ps.ok) {
    await admin.from('fare_authorizations').update({
      status: 'authorized',
      updated_at: new Date().toISOString(),
    }).eq('id', auth.id);
    return { ok: false, message: ps.message ?? 'Paystack capture failed' };
  }

  const psData = (ps.data ?? {}) as Record<string, unknown>;
  const txnReference = String(psData.reference ?? captureRef);
  const platformFee = opts.platformFee ?? 0;

  const { data: txn, error: txErr } = await admin.from('transactions').insert({
    merchant_id: auth.merchant_id,
    reference: txnReference,
    amount: captureAmount,
    card_amount: captureAmount,
    platform_fee: platformFee,
    currency: auth.currency,
    status: String(psData.status ?? 'success') === 'success' ? 'success' : 'pending',
    buyer_email: auth.buyer_email,
    buyer_authorised: true,
    buyer_authorised_at: now,
  }).select('id').single();

  if (txErr) {
    return { ok: false, message: txErr.message || 'Could not record capture transaction' };
  }

  const { data: updated, error: upErr } = await admin
    .from('fare_authorizations')
    .update({
      status: 'captured',
      captured_at: now,
      capture_reference: captureRef,
      paystack_reference: txnReference,
      transaction_id: txn?.id ?? null,
      updated_at: now,
    })
    .eq('id', auth.id)
    .select()
    .single();

  if (upErr || !updated) {
    return { ok: false, message: upErr?.message ?? 'Capture state update failed' };
  }

  return { ok: true, row: updated as FareAuthRow };
}

export async function releaseFareAuthorization(
  admin: SupabaseClient,
  opts: {
    authorizationId: string;
    merchantId?: string;
    paystackSecret?: string;
    recordOnly?: boolean;
  },
): Promise<{ ok: true; row: FareAuthRow } | { ok: false; message: string }> {
  let q = admin.from('fare_authorizations').select('*').eq('id', opts.authorizationId);
  if (opts.merchantId) q = q.eq('merchant_id', opts.merchantId);
  const { data: row } = await q.maybeSingle();
  if (!row) return { ok: false, message: 'Authorization not found' };

  const auth = row as FareAuthRow;
  if (auth.status === 'voided') return { ok: true, row: auth };
  if (auth.status === 'captured') {
    return { ok: false, message: 'Authorization already captured' };
  }

  if (auth.paystack_preauth_reference && opts.paystackSecret && !opts.recordOnly) {
    const ps = await releasePaystackPreauthorization(opts.paystackSecret, auth.paystack_preauth_reference);
    if (!ps.ok) {
      return { ok: false, message: ps.message ?? 'Paystack release failed' };
    }
  }

  const now = new Date().toISOString();
  const { data: updated, error } = await admin
    .from('fare_authorizations')
    .update({ status: 'voided', updated_at: now })
    .eq('id', auth.id)
    .select()
    .single();

  if (error || !updated) {
    return { ok: false, message: error?.message ?? 'Void failed' };
  }
  return { ok: true, row: updated as FareAuthRow };
}

export async function markFareAuthorizationCaptured(
  admin: SupabaseClient,
  captureReference: string,
  transactionId?: string,
): Promise<boolean> {
  const now = new Date().toISOString();
  const { data } = await admin
    .from('fare_authorizations')
    .update({
      status: 'captured',
      captured_at: now,
      updated_at: now,
      transaction_id: transactionId ?? null,
    })
    .eq('capture_reference', captureReference)
    .in('status', ['capture_initiated', 'authorized'])
    .select('id')
    .maybeSingle();
  return !!data;
}

export async function markFareAuthorizationCapturedById(
  admin: SupabaseClient,
  authorizationId: string,
  transactionId?: string,
): Promise<boolean> {
  const now = new Date().toISOString();
  const { data } = await admin
    .from('fare_authorizations')
    .update({
      status: 'captured',
      captured_at: now,
      updated_at: now,
      transaction_id: transactionId ?? null,
    })
    .eq('id', authorizationId)
    .in('status', ['capture_initiated', 'authorized', 'pending_preauth'])
    .select('id')
    .maybeSingle();
  return !!data;
}

export async function resolveFareAuthByPreauthReference(
  admin: SupabaseClient,
  reference: string,
): Promise<FareAuthRow | null> {
  const { data } = await admin
    .from('fare_authorizations')
    .select('*')
    .eq('paystack_preauth_reference', reference)
    .maybeSingle();
  return (data as FareAuthRow) ?? null;
}

// AI subscription + monthly credit limits for merchant growth features.

export type SubscriptionPlan = 'free' | 'premium' | 'business';

export const AI_MONTHLY_LIMITS: Record<SubscriptionPlan, number> = {
  free: 10,
  premium: 500,
  business: 5000,
};

export const PREMIUM_AI_ACTIONS = new Set([
  'ask',
  'insights',
  'marketing',
  'sales_coach',
  'find_leads',
  'suggest_nfc_tags',
  'scan_receipt',
  'catalog',
]);

export function effectiveSubscriptionPlan(row: {
  subscription_plan?: string | null;
  merchant_plan?: string | null;
  subscription_status?: string | null;
}): SubscriptionPlan {
  const plan = String(row.subscription_plan ?? '').toLowerCase();
  if (plan === 'premium' || plan === 'business') return plan;
  if (row.merchant_plan === 'premium' && row.subscription_status === 'active') return 'premium';
  return 'free';
}

export function monthlyAiLimit(plan: SubscriptionPlan): number {
  return AI_MONTHLY_LIMITS[plan];
}

export type AiCreditResult =
  | { ok: true; plan: SubscriptionPlan; credits_remaining: number; credits_limit: number }
  | { ok: false; code: 'PREMIUM_REQUIRED' | 'CREDITS_EXHAUSTED'; message: string; credits_remaining: number; credits_limit: number; plan: SubscriptionPlan };

export function checkAiCredits(row: {
  subscription_plan?: string | null;
  merchant_plan?: string | null;
  subscription_status?: string | null;
  ai_credits?: number | null;
  ai_credits_used?: number | null;
}, action: string): AiCreditResult {
  if (!PREMIUM_AI_ACTIONS.has(action)) {
    return { ok: true, plan: 'free', credits_remaining: 999, credits_limit: 999 };
  }

  const plan = effectiveSubscriptionPlan(row);
  const limit = Number(row.ai_credits ?? monthlyAiLimit(plan)) || monthlyAiLimit(plan);
  const used = Number(row.ai_credits_used ?? 0);
  const remaining = Math.max(0, limit - used);

  if (remaining <= 0) {
    if (plan === 'free') {
      return {
        ok: false,
        code: 'PREMIUM_REQUIRED',
        message: 'You have used your 10 free AI requests this month. Upgrade to Premium for 500 AI requests and the full growth suite.',
        credits_remaining: 0,
        credits_limit: limit,
        plan,
      };
    }
    return {
      ok: false,
      code: 'CREDITS_EXHAUSTED',
      message: `You have used all ${limit} AI credits this month. Credits reset at the start of next month.`,
      credits_remaining: 0,
      credits_limit: limit,
      plan,
    };
  }

  return { ok: true, plan, credits_remaining: remaining, credits_limit: limit };
}

export function premiumActivationPatch(now = new Date()) {
  const end = new Date(now);
  end.setMonth(end.getMonth() + 1);
  return {
    merchant_plan: 'premium',
    subscription_plan: 'premium',
    subscription_status: 'active',
    subscription_start: now.toISOString(),
    subscription_end: end.toISOString(),
    ai_credits: AI_MONTHLY_LIMITS.premium,
    ai_credits_used: 0,
    ai_credits_reset_at: new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1)).toISOString(),
  };
}

export function freePlanPatch(now = new Date()) {
  return {
    merchant_plan: 'small',
    subscription_plan: 'free',
    subscription_status: 'cancelled',
    ai_credits: AI_MONTHLY_LIMITS.free,
    ai_credits_used: 0,
    ai_credits_reset_at: new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1)).toISOString(),
  };
}

/** Platform fee plan resolution — premium subscribers pay 0% while active. */

export type MerchantPlan = 'small' | 'marketplace' | 'premium' | 'founding';

export function defaultPlanPercent(plan: MerchantPlan): number {
  switch (plan) {
    case 'founding':
      return 1.5;
    case 'marketplace':
      return 5;
    case 'premium':
      return 0;
    default:
      return 2;
  }
}

export function feePlanFromMerchant(merchant: {
  merchant_plan?: string | null;
  subscription_status?: string | null;
}): MerchantPlan {
  const raw = String(merchant.merchant_plan ?? 'small');
  if (raw === 'founding') return 'founding';
  if (raw === 'marketplace') return 'marketplace';
  if (raw === 'premium' && merchant.subscription_status === 'active') return 'premium';
  return 'small';
}

import { minChargeMessage, minChargeSubunits } from './paymentLimits.ts';

const PAYSTACK_BASE = 'https://api.paystack.co';

export async function paystackGet(secret: string, path: string) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    headers: { Authorization: `Bearer ${secret}` },
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok || json?.status === false) {
    return {
      ok: false,
      message: (json as { message?: string }).message || res.statusText,
      data: (json as { data?: unknown }).data,
    };
  }
  return { ok: true, data: (json as { data?: unknown }).data };
}

export async function paystackPost(secret: string, path: string, body: unknown) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${secret}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok || json?.status === false) {
    return {
      ok: false,
      message: (json as { message?: string }).message || res.statusText,
      data: (json as { data?: unknown }).data,
    };
  }
  return { ok: true, data: (json as { data?: unknown }).data };
}

export async function paystackPut(secret: string, path: string, body: unknown) {
  const res = await fetch(`${PAYSTACK_BASE}${path}`, {
    method: 'PUT',
    headers: {
      Authorization: `Bearer ${secret}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });
  const json = await res.json().catch(() => ({}));
  if (!res.ok || json?.status === false) {
    return {
      ok: false,
      message: (json as { message?: string }).message || res.statusText,
      data: (json as { data?: unknown }).data,
    };
  }
  return { ok: true, data: (json as { data?: unknown }).data };
}

/** Master Paystack integration balance (major units, e.g. ZAR). */
export async function fetchPaystackBalance(secret: string) {
  const r = await paystackGet(secret, '/balance');
  if (!r.ok) return r;
  const rows = (r.data as Array<{ balance?: number; currency?: string }>) ?? [];
  const zar = rows.find((x) => String(x.currency ?? '').toUpperCase() === 'ZAR') ?? rows[0];
  const balanceSub = Number(zar?.balance ?? 0);
  return {
    ok: true,
    balance: balanceSub / 100,
    currency: String(zar?.currency ?? 'ZAR').toUpperCase(),
    raw: rows,
  };
}

export type CreateRecipientInput = {
  name: string;
  account_number: string;
  bank_code: string;
  currency?: string;
};

export async function createPaystackTransferRecipient(secret: string, input: CreateRecipientInput) {
  const currency = String(input.currency ?? 'ZAR').toUpperCase();
  const type = currency === 'ZAR' ? 'basa' : 'nuban';
  return await paystackPost(secret, '/transferrecipient', {
    type,
    name: input.name,
    account_number: input.account_number,
    bank_code: input.bank_code,
    currency,
  });
}

export type InitiateTransferInput = {
  amountMajor: number;
  recipientCode: string;
  reason: string;
  reference: string;
  currency?: string;
  merchantId?: string;
};

export async function initiatePaystackTransfer(secret: string, input: InitiateTransferInput) {
  const amountSub = Math.round(input.amountMajor * 100);
  if (amountSub < 100) {
    return { ok: false, message: 'Minimum transfer amount is R1.00' };
  }
  return await paystackPost(secret, '/transfer', {
    source: 'balance',
    amount: amountSub,
    recipient: input.recipientCode,
    reason: input.reason.slice(0, 100) || 'RedFace transfer',
    reference: input.reference,
    currency: String(input.currency ?? 'ZAR').toUpperCase(),
    metadata: input.merchantId ? { merchant_id: input.merchantId } : {},
  });
}

export type ChargeAuthorizationInput = {
  email: string;
  amountMajor: number;
  authorizationCode: string;
  reference: string;
  currency?: string;
  metadata?: Record<string, unknown>;
  subaccount?: string;
  splitCode?: string;
  transactionCharge?: number;
};

export async function chargePaystackAuthorization(secret: string, input: ChargeAuthorizationInput) {
  const amountSub = Math.round(input.amountMajor * 100);
  const currency = String(input.currency ?? 'ZAR').toUpperCase();
  const minSub = minChargeSubunits(currency);
  if (amountSub < minSub) {
    return { ok: false, message: minChargeMessage(currency) };
  }
  const body: Record<string, unknown> = {
    email: input.email,
    amount: amountSub,
    authorization_code: input.authorizationCode,
    reference: input.reference,
    currency: String(input.currency ?? 'ZAR').toUpperCase(),
    metadata: input.metadata ?? {},
  };
  if (input.splitCode) {
    body.split_code = input.splitCode;
  } else if (input.subaccount) {
    body.subaccount = input.subaccount;
    body.bearer = 'subaccount';
    if (input.transactionCharge && input.transactionCharge > 0) {
      body.transaction_charge = input.transactionCharge;
    }
  }
  return await paystackPost(secret, '/transaction/charge_authorization', body);
}

export type ChargeCardInput = {
  email: string;
  amountMajor: number;
  reference: string;
  currency?: string;
  card: {
    number: string;
    cvv: string;
    expiry_month: string;
    expiry_year: string;
  };
  metadata?: Record<string, unknown>;
  subaccount?: string;
  splitCode?: string;
  transactionCharge?: number;
};

/** Charge a card directly via Paystack — card data must never be logged or stored. */
export async function chargePaystackCard(secret: string, input: ChargeCardInput) {
  const amountSub = Math.round(input.amountMajor * 100);
  const currency = String(input.currency ?? 'ZAR').toUpperCase();
  const minSub = minChargeSubunits(currency);
  if (amountSub < minSub) {
    return { ok: false, message: minChargeMessage(currency) };
  }
  const body: Record<string, unknown> = {
    email: input.email,
    amount: amountSub,
    reference: input.reference,
    currency: String(input.currency ?? 'ZAR').toUpperCase(),
    card: {
      number: input.card.number.replace(/\D/g, ''),
      cvv: input.card.cvv.replace(/\D/g, ''),
      expiry_month: input.card.expiry_month.padStart(2, '0'),
      expiry_year: input.card.expiry_year.length === 2
        ? `20${input.card.expiry_year}`
        : input.card.expiry_year,
    },
    metadata: input.metadata ?? {},
  };
  if (input.splitCode) {
    body.split_code = input.splitCode;
  } else if (input.subaccount) {
    body.subaccount = input.subaccount;
    body.bearer = 'subaccount';
    if (input.transactionCharge && input.transactionCharge > 0) {
      body.transaction_charge = input.transactionCharge;
    }
  }
  return await paystackPost(secret, '/charge', body);
}

export async function createOrFetchPaystackCustomer(
  secret: string,
  input: { email: string; first_name: string; last_name: string; phone?: string | null },
) {
  const email = input.email.trim().toLowerCase();
  const existing = await paystackGet(secret, `/customer/${encodeURIComponent(email)}`);
  if (existing.ok) {
    const row = (existing.data ?? {}) as Record<string, unknown>;
    if (row.customer_code) return { ok: true, data: row };
  }
  return await paystackPost(secret, '/customer', {
    email,
