import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { cartLabel, resolveCartItems, type CartLine } from './cartItems.ts';
import {
  claimPaymentRequest,
  completePaymentRequest,
  idempotentSessionMessage,
} from './idempotency.ts';
import { recordPaymentLedgerEntry } from './ledgerEngine.ts';
import { selectProcessingRail, routingDecisionToMeta } from './paymentRouting.ts';

export type { CartLine };
export { cartLabel, resolveCartItems };

const ACTIVE_SESSION_STATUSES = new Set(['waiting', 'opened', 'processing']);

export function isActivePaymentSessionStatus(status: string): boolean {
  return ACTIVE_SESSION_STATUSES.has(status);
}

export type PaymentSessionRow = {
  id: string;
  merchant_id: string;
  payment_object_id: string | null;
  public_token: string;
  amount: number;
  currency: string;
  label: string | null;
  status: string;
  expires_at: string;
  metadata?: Record<string, unknown> | null;
};

export async function cancelOpenSessions(
  admin: SupabaseClient,
  merchantId: string,
  paymentObjectId: string | null,
) {
  let q = admin
    .from('payment_sessions')
    .update({ status: 'cancelled', updated_at: new Date().toISOString() })
    .eq('merchant_id', merchantId)
    .in('status', ['waiting', 'opened', 'processing']);
  if (paymentObjectId) {
    q = q.eq('payment_object_id', paymentObjectId);
  } else {
    q = q.is('payment_object_id', null);
  }
  await q;
}

export async function validatePaymentSessionForInit(
  admin: SupabaseClient,
  opts: {
    sessionId?: string | null;
    sessionToken?: string | null;
    merchantId: string;
    amount: number;
    reference: string;
  },
): Promise<{ ok: true; session: PaymentSessionRow } | { ok: false; message: string }> {
  const { sessionId, sessionToken, merchantId, amount, reference } = opts;
  if (!sessionId && !sessionToken) {
    return { ok: false, message: 'payment_session required' };
  }

  await admin.rpc('expire_payment_sessions').then(() => {}, () => {});

  let q = admin
    .from('payment_sessions')
    .select('id, merchant_id, payment_object_id, public_token, amount, currency, label, status, expires_at')
    .eq('merchant_id', merchantId)
    .in('status', ['waiting', 'opened', 'processing'])
    .gt('expires_at', new Date().toISOString());

  if (sessionId) q = q.eq('id', sessionId);
  else if (sessionToken) q = q.eq('public_token', sessionToken);
  else return { ok: false, message: 'payment_session required' };

  const { data: session, error } = await q.maybeSingle();
  if (error || !session) {
    return { ok: false, message: 'Payment session not found or expired. Ask the merchant to press Ready again.' };
  }

  const sessionAmount = Number(session.amount);
  if (Math.abs(sessionAmount - amount) > 0.009) {
    return {
      ok: false,
      message: `Amount must match the merchant session (${sessionAmount} ${session.currency}).`,
    };
  }

  await admin.rpc('mark_payment_session_processing', {
    p_session_id: session.id,
    p_reference: reference,
  });

  return { ok: true, session: session as PaymentSessionRow };
}

export async function markSessionPaid(
  admin: SupabaseClient,
  reference: string,
  transactionId?: string | null,
) {
  await admin.rpc('mark_payment_session_paid', {
    p_reference: reference,
    p_transaction_id: transactionId ?? null,
  });
  // Ledger commitment: providers are evidence, the Ledger is truth.
  // Idempotent — duplicate webhooks and sync/async races collapse into one entry.
  await recordPaymentLedgerEntry(admin, { reference });
}

export async function markSessionFailed(admin: SupabaseClient, reference: string) {
  await admin.rpc('mark_payment_session_failed', { p_reference: reference });
}

export async function reopenPaymentSession(admin: SupabaseClient, sessionId: string) {
  await admin.rpc('mark_payment_session_reopen', { p_session_id: sessionId });
}

const SESSION_SELECT =
  'id, public_token, amount, currency, label, status, expires_at, payment_object_id, cart_items';

export async function createPaymentSessionRecord(
  admin: SupabaseClient,
  opts: {
    merchantId: string;
    amount?: number;
    currency?: string;
    label?: string | null;
    paymentObjectId?: string | null;
    ttlSeconds?: number;
    cartItems?: unknown;
    createdBy?: string | null;
    idempotencyKey?: string | null;
    requestType?: 'payment_session' | 'table_pay';
    metadata?: Record<string, unknown> | null;
    /** WHAT the merchant wants to achieve (never a provider). Defaults to collect_payment. */
    businessIntent?: string | null;
    /** HOW the customer will authorise, when known at creation (qr, nfc_tap, table_pay, ...). */
    captureMethod?: string | null;
    /** Merchant operating country for Routing Engine (ISO 3166-1 alpha-2). */
    country?: string | null;
    softposPartner?: 'istore_tap' | 'yoco_tap' | 'stripe_terminal' | null;
    stripeTerminalEntitled?: boolean;
  },
): Promise<
  | {
    ok: true;
    session: Record<string, unknown>;
    cartItems: CartLine[];
    idempotent?: boolean;
    retryCount?: number;
    message?: string | null;
  }
  | { ok: false; error: string; status?: number }
> {
  let amount = Number(opts.amount ?? 0);
  const currency = String(opts.currency ?? 'ZAR').trim() || 'ZAR';
  let label = String(opts.label ?? '').trim() || null;
  let paymentObjectId = String(opts.paymentObjectId ?? '').trim() || null;
  const ttlSeconds = Math.min(3600, Math.max(60, Number(opts.ttlSeconds ?? 900)));
  let cartItemsStored: CartLine[] = [];

  if (opts.cartItems != null && Array.isArray(opts.cartItems) && opts.cartItems.length > 0) {
    const resolved = await resolveCartItems(admin, opts.merchantId, opts.cartItems);
    if ('error' in resolved) return { ok: false, error: resolved.error, status: 400 };
    amount = resolved.total;
    cartItemsStored = resolved.items;
  }

  if (!amount || amount <= 0) {
    return { ok: false, error: 'amount is required', status: 400 };
  }

  const idempotencyKey = String(opts.idempotencyKey ?? '').trim() || null;
  const requestType = opts.requestType ?? 'payment_session';

  if (idempotencyKey) {
    const claim = await claimPaymentRequest(admin, {
      merchantId: opts.merchantId,
      idempotencyKey,
      requestType,
      amount,
      currency,
      requestPayload: {
        label,
        payment_object_id: paymentObjectId,
        cart_count: cartItemsStored.length,
      },
    });
    if (claim.ok && !claim.created && claim.request.payment_session_id) {
      const { data: existing } = await admin
        .from('payment_sessions')
        .select(SESSION_SELECT)
        .eq('id', claim.request.payment_session_id)
        .eq('merchant_id', opts.merchantId)
        .maybeSingle();
      if (existing) {
        const storedCart = Array.isArray(existing.cart_items) ? existing.cart_items as CartLine[] : cartItemsStored;
        if (isActivePaymentSessionStatus(String(existing.status))) {
          return {
            ok: true,
            session: existing,
            cartItems: storedCart,
            idempotent: true,
            retryCount: claim.retryCount,
            message: idempotentSessionMessage(String(existing.status)),
          };
        }
        // Stale idempotency (paid / expired / cancelled) — create a fresh session below.
      }
    }
  }

  if (!paymentObjectId) {
    const { data: primary } = await admin
      .from('payment_objects')
      .select('id')
      .eq('merchant_id', opts.merchantId)
      .eq('status', 'active')
      .order('created_at', { ascending: true })
      .limit(1)
      .maybeSingle();
    paymentObjectId = primary?.id ?? null;
  }

  let terminalLabel: string | null = null;
  let terminalTapCode: string | null = null;
  if (paymentObjectId) {
    const { data: obj } = await admin
      .from('payment_objects')
      .select('id, label, tap_code')
      .eq('id', paymentObjectId)
      .eq('merchant_id', opts.merchantId)
      .eq('status', 'active')
      .maybeSingle();
    if (!obj) return { ok: false, error: 'Terminal not found', status: 404 };
    terminalLabel = obj.label ? String(obj.label) : null;
    terminalTapCode = obj.tap_code ? String(obj.tap_code) : null;
  }

  await admin.rpc('expire_payment_sessions').then(() => {}, () => {});
  await cancelOpenSessions(admin, opts.merchantId, paymentObjectId);

  const expiresAt = new Date(Date.now() + ttlSeconds * 1000).toISOString();
  const rawMetadata = opts.metadata && typeof opts.metadata === 'object'
    ? opts.metadata
    : {};
  // Commerce Intelligence: every session carries enough business context to
  // explain who / what / where — notes are never the only source of truth.
  const sessionMetadata: Record<string, unknown> = {
    ...rawMetadata,
  };
  if (paymentObjectId) {
    sessionMetadata.payment_object_id = paymentObjectId;
    if (terminalLabel) sessionMetadata.terminal_label = terminalLabel;
    if (terminalTapCode) sessionMetadata.terminal_tap_code = terminalTapCode;
  }
  if (cartItemsStored.length) {
    sessionMetadata.line_item_count = cartItemsStored.length;
    sessionMetadata.has_line_items = true;
  }
  const hasPosSale = Boolean(String(sessionMetadata.pos_sale_id ?? '').trim());
  const hasCart = cartItemsStored.length > 0;
  const businessIntent = String(opts.businessIntent ?? '').trim().toLowerCase()
    || (requestType === 'table_pay' || hasPosSale || hasCart ? 'complete_sale' : 'collect_payment');
  let captureMethod = String(opts.captureMethod ?? '').trim().toLowerCase() || null;
  if (!captureMethod) {
    if (requestType === 'table_pay') captureMethod = 'table_pay';
    else if (paymentObjectId) captureMethod = 'nfc_tap';
    else if (hasPosSale) captureMethod = 'checkout';
    else captureMethod = 'payment_link';
  }
  sessionMetadata.business_intent = businessIntent;
  sessionMetadata.capture_method = captureMethod;
  const routing = selectProcessingRail({
    merchantId: opts.merchantId,
    currency,
    country: opts.country ?? null,
    captureMethod,
    businessIntent,
    softposPartner: opts.softposPartner ?? null,
    stripeTerminalEntitled: opts.stripeTerminalEntitled,
  });
  sessionMetadata.routing = routingDecisionToMeta(routing);
  sessionMetadata.processing_rail = routing.rail;
  const { data: row, error } = await admin.from('payment_sessions').insert({
    merchant_id: opts.merchantId,
    payment_object_id: paymentObjectId,
    amount,
    currency,
    label: label || (cartItemsStored.length ? cartLabel(cartItemsStored) : null),
    cart_items: cartItemsStored,
    metadata: sessionMetadata,
    status: 'waiting',
    expires_at: expiresAt,
    created_by: opts.createdBy ?? null,
    business_intent: businessIntent,
    capture_method: captureMethod,
    processing_rail: routing.rail,
  }).select(SESSION_SELECT).single();

  if (error || !row) {
    return { ok: false, error: error?.message || 'Could not create payment session', status: 500 };
  }

  if (idempotencyKey) {
    await completePaymentRequest(admin, {
      merchantId: opts.merchantId,
      idempotencyKey,
      requestType,
      status: 'processing',
      paymentSessionId: String(row.id),
      responsePayload: { session: row },
    });
  }

  return { ok: true, session: row, cartItems: cartItemsStored, idempotent: false, retryCount: 0 };
}

/**
 * Ledger Engine — the mandatory write path for payment truth.
 *
 * Platform Invariants (docs/codex/platform/platform-invariants.md):
 * - IX: The Ledger is the source of truth; providers are external evidence.
 * - III/IV: Every write is idempotent; entries are immutable after commit.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { appendPlatformPaymentEvent } from './platformPaymentSpine.ts';
import { consumePaymentRecorded } from './consumePaymentRecorded.ts';
import {
  createBusinessFactEnvelope,
  envelopeIntoPayload,
} from './businessFactEnvelope.ts';

export type LedgerRecordResult = {
  ok: boolean;
  created: boolean;
  error?: string;
  factId?: string | null;
};

export async function recordPaymentLedgerEntry(
  admin: SupabaseClient,
  opts: {
    reference: string;
    processingRail?: string | null;
    app?: string | null;
  },
): Promise<LedgerRecordResult> {
  const reference = String(opts.reference ?? '').trim();
  if (!reference) return { ok: false, created: false, error: 'reference_required' };

  const { data, error } = await admin.rpc('record_payment_ledger_entry', {
    p_reference: reference,
    p_processing_rail: opts.processingRail ?? null,
  });
  if (error) {
    console.error('record_payment_ledger_entry', reference, error.message);
    return { ok: false, created: false, error: error.message };
  }

  const row = (data ?? {}) as Record<string, unknown>;
  if (row.ok !== true) {
    return { ok: false, created: false, error: String(row.error ?? 'ledger_write_failed') };
  }

  const created = row.created === true;
  let factId: string | null = null;
  if (created) {
    const merchantId = typeof row.merchant_id === 'string' ? row.merchant_id : null;
    const envelope = createBusinessFactEnvelope({
      type: 'payment.recorded',
      producer: 'commerce-kernel.ledger',
      merchantId,
      reference,
      payload: {
        txn_key: row.txn_key ?? null,
        business_intent: row.business_intent ?? null,
        processing_rail: row.processing_rail ?? opts.processingRail ?? null,
      },
    });

    factId = await appendPlatformPaymentEvent(admin, {
      eventType: envelope.type,
      reference,
      idempotencyKey: `ledger:${reference}`,
      app: opts.app ?? null,
      merchantId,
      amount: typeof row.amount === 'number' ? row.amount : Number(row.amount ?? 0) || null,
      currency: typeof row.currency === 'string' ? row.currency : null,
      payload: envelopeIntoPayload(envelope),
      correlationId: envelope.correlation_id,
      causationId: envelope.causation_id,
      eventVersion: envelope.version,
      producer: envelope.producer,
    });

    await consumePaymentRecorded(admin, {
      reference,
      merchantId,
      amount: typeof row.amount === 'number' ? row.amount : Number(row.amount ?? 0) || null,
      currency: typeof row.currency === 'string' ? row.currency : null,
      businessIntent: typeof row.business_intent === 'string' ? row.business_intent : null,
      processingRail: typeof row.processing_rail === 'string' ? row.processing_rail : null,
      txnKey: typeof row.txn_key === 'string' ? row.txn_key : null,
      correlationId: envelope.correlation_id,
      causationId: factId ?? envelope.id,
    });
  }
  return { ok: true, created, factId };
}

/**
 * Merchant Capabilities API — registry-driven discovery (Capability Registry v1).
 *
 * Merchants buy outcomes; developers buy kernels. Response uses merchant-facing
 * keys only. Each capability is a feature contract: enabled + why/why not.
 *
 * @see docs/codex/platform/financial-abstraction-layer.md
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import {
  CAPABILITY_REGISTRY,
  type CapabilityDescriptor,
  type ProcessingRail,
  selectProcessingRail,
} from './paymentRouting.ts';
import { listPaymentTerminals, type PaymentTerminal } from './paymentTerminal.ts';

export type CapabilityState = {
  enabled: boolean;
  status: 'active' | 'unavailable' | 'planned';
  configured: boolean;
  requirements: string[];
  reason: string | null;
};

export type MerchantCapabilityMap = {
  paymentLinks: CapabilityState;
  qr: CapabilityState;
  nfcTap: CapabilityState;
  manualCard: CapabilityState;
  checkout: CapabilityState;
  tablePay: CapabilityState;
  cash: CapabilityState;
  storeCredit: CapabilityState;
  cardPayments: CapabilityState;
  bankTransfer: CapabilityState;
  crypto: CapabilityState;
  voiceCharge: CapabilityState;
  appleTap: CapabilityState;
  softpos: CapabilityState;
};

/** Flat booleans for simple UI checks. Prefer CapabilityState when showing reasons. */
export type MerchantCapabilityFlags = {
  [K in keyof MerchantCapabilityMap]: boolean;
};

export type MerchantCapabilitiesResponse = {
  merchant_id: string;
  country: string | null;
  currency: string;
  capabilities: MerchantCapabilityMap;
  /** Convenience booleans derived from capabilities.*.enabled */
  flags: MerchantCapabilityFlags;
  default_rails: Partial<Record<string, ProcessingRail>>;
  /** SoftPOS-ready terminals (NFC cards, SoftPOS, QR, cash, link). */
  terminals: PaymentTerminal[];
  registry: Array<CapabilityDescriptor & { available: boolean; missing_requirements: string[] }>;
};

type MerchantRow = {
  id: string;
  country: string | null;
  status: string;
  paystack_subaccount: string | null;
  paystack_split_code: string | null;
};

const REASON_LABEL: Record<string, string> = {
  merchant_approved: 'Business is not approved yet',
  country: 'Not available in this country',
  paystack_subaccount: 'Card payments are not set up yet',
  payment_object: 'No active terminal or NFC tag',
  store_credit_program: 'No active store credit issued yet',
  tap_partner_onboarding: 'Partner onboarding has not been completed',
  ios_device: 'Requires a compatible iPhone',
  planned: 'Coming soon',
  restaurant_tables: 'Floor tables are not set up',
  dedicated_account: 'Dedicated bank account is not active',
  crypto_wallets: 'Crypto wallets are not configured',
};

function hasPaystackRoute(m: MerchantRow): boolean {
  return String(m.paystack_split_code || m.paystack_subaccount || '').trim().length > 0;
}

function countryAllowed(desc: CapabilityDescriptor, country: string | null): boolean {
  if (desc.countries === 'all') return true;
  const c = String(country ?? '').trim().toUpperCase();
  return desc.countries.some((x) => x.toUpperCase() === c);
}

function evaluateDescriptor(
  desc: CapabilityDescriptor,
  ctx: {
    merchant: MerchantRow;
    hasPaymentObject: boolean;
    hasTables: boolean;
    hasStoreCreditProgram: boolean;
    hasDedicatedAccount: boolean;
    hasCrypto: boolean;
  },
): { available: boolean; missing: string[] } {
  const missing: string[] = [];
  if (ctx.merchant.status !== 'approved') missing.push('merchant_approved');
  if (!countryAllowed(desc, ctx.merchant.country)) missing.push('country');

  for (const req of desc.requirements) {
    if (req === 'paystack_subaccount' && !hasPaystackRoute(ctx.merchant)) missing.push(req);
    if (req === 'payment_object' && !ctx.hasPaymentObject) missing.push(req);
    if (req === 'store_credit_program' && !ctx.hasStoreCreditProgram) missing.push(req);
    if (req === 'dedicated_account' && !ctx.hasDedicatedAccount) missing.push(req);
    if (req === 'crypto_wallets' && !ctx.hasCrypto) missing.push(req);
    if (req === 'tap_partner_onboarding') missing.push(req);
    if (req === 'ios_device') missing.push(req);
  }

  if (desc.id === 'store_credit_rail' || desc.id === 'store_credit_capture') {
    if (!ctx.hasStoreCreditProgram) missing.push('store_credit_program');
  }
  if (desc.status === 'planned') missing.push('planned');

  return { available: missing.length === 0, missing: [...new Set(missing)] };
}

function toState(
  enabled: boolean,
  missing: string[],
  opts: { planned?: boolean; configured?: boolean } = {},
): CapabilityState {
  const requirements = missing.filter((m) => m !== 'planned' && m !== 'merchant_approved');
  const primary = missing[0] ?? null;
  return {
    enabled,
    status: opts.planned || missing.includes('planned')
      ? 'planned'
      : enabled
        ? 'active'
        : 'unavailable',
    configured: opts.configured ?? enabled,
    requirements,
    reason: enabled ? null : (primary ? (REASON_LABEL[primary] ?? primary) : 'Unavailable'),
  };
}

function flagsFromMap(map: MerchantCapabilityMap): MerchantCapabilityFlags {
  return Object.fromEntries(
    Object.entries(map).map(([k, v]) => [k, (v as CapabilityState).enabled]),
  ) as MerchantCapabilityFlags;
}

export async function resolveMerchantCapabilities(
  admin: SupabaseClient,
  merchantId: string,
): Promise<{ ok: true; data: MerchantCapabilitiesResponse } | { ok: false; error: string }> {
  const id = String(merchantId ?? '').trim();
  if (!id) return { ok: false, error: 'merchant_id_required' };

  const { data: merchant, error } = await admin
    .from('merchants')
    .select('id, country, status, paystack_subaccount, paystack_split_code')
    .eq('id', id)
    .maybeSingle();
  if (error || !merchant) return { ok: false, error: 'merchant_not_found' };

  const [
    { count: poCount },
    { count: tableCount },
    { count: creditCount },
    { count: dedicatedCount },
    { data: cryptoRow },
  ] = await Promise.all([
    admin.from('payment_objects').select('id', { count: 'exact', head: true })
      .eq('merchant_id', id).eq('status', 'active'),
    admin.from('restaurant_tables').select('id', { count: 'exact', head: true })
      .eq('merchant_id', id),
    admin.from('merchant_store_credits').select('id', { count: 'exact', head: true })
      .eq('merchant_id', id).eq('status', 'active'),
    admin.from('merchant_dedicated_accounts').select('id', { count: 'exact', head: true })
      .eq('merchant_id', id).eq('status', 'active'),
    admin.from('merchant_crypto_settings').select('enabled, btc_address, eth_address, usdt_trc20_address, usdt_erc20_address')
      .eq('merchant_id', id).maybeSingle(),
  ]);

  const hasCrypto = Boolean(
    cryptoRow?.enabled
    && (cryptoRow.btc_address || cryptoRow.eth_address || cryptoRow.usdt_trc20_address || cryptoRow.usdt_erc20_address),
  );

  const ctx = {
    merchant: merchant as MerchantRow,
    hasPaymentObject: (poCount ?? 0) > 0,
    hasTables: (tableCount ?? 0) > 0,
    hasStoreCreditProgram: (creditCount ?? 0) > 0,
    hasDedicatedAccount: (dedicatedCount ?? 0) > 0,
    hasCrypto,
  };

  const country = merchant.country ?? null;
  const currency = country === 'NG' ? 'NGN' : country === 'GH' ? 'GHS' : country === 'KE' ? 'KES' : 'ZAR';

  const registry = CAPABILITY_REGISTRY.map((desc) => {
    const { available, missing } = evaluateDescriptor(desc, ctx);
    return { ...desc, available, missing_requirements: missing };
  });

  const byId = (capId: string) => registry.find((r) => r.id === capId);

  const paymentLink = byId('payment_link_capture');
  const qr = byId('qr_capture');
  const nfc = byId('nfc_tap_capture');
  const manual = byId('manual_card_capture');
  const cash = byId('cash_capture');
  const storeCredit = byId('store_credit_capture') ?? byId('store_credit_rail');
  const paystack = byId('paystack_rail');
  const apple = byId('apple_tap_capture');
  const softpos = byId('softpos_capture');
  const bank = byId('bank_transfer_capture');
  const crypto = byId('crypto_capture');

  const cardPayments = paystack?.available ?? false;

  const capabilities: MerchantCapabilityMap = {
    paymentLinks: toState(paymentLink?.available ?? false, paymentLink?.missing_requirements ?? []),
    qr: toState(qr?.available ?? false, qr?.missing_requirements ?? []),
    nfcTap: toState(nfc?.available ?? false, nfc?.missing_requirements ?? [], {
      configured: ctx.hasPaymentObject,
    }),
    manualCard: toState(
      (manual?.available ?? false) && cardPayments,
      [...(manual?.missing_requirements ?? []), ...(cardPayments ? [] : ['paystack_subaccount'])],
    ),
    checkout: toState(cardPayments || (paymentLink?.available ?? false), cardPayments ? [] : ['paystack_subaccount']),
    tablePay: toState(
      ctx.hasTables && (paymentLink?.available ?? false),
      ctx.hasTables ? (paymentLink?.missing_requirements ?? []) : ['restaurant_tables'],
      { configured: ctx.hasTables },
    ),
    cash: toState(cash?.available ?? false, cash?.missing_requirements ?? []),
    storeCredit: toState(storeCredit?.available ?? false, storeCredit?.missing_requirements ?? [], {
      configured: ctx.hasStoreCreditProgram,
    }),
    cardPayments: toState(cardPayments, paystack?.missing_requirements ?? [], {
      configured: hasPaystackRoute(merchant as MerchantRow),
    }),
    bankTransfer: toState(bank?.available ?? false, bank?.missing_requirements ?? [], {
      configured: ctx.hasDedicatedAccount,
    }),
    crypto: toState(crypto?.available ?? false, crypto?.missing_requirements ?? [], {
      configured: hasCrypto,
    }),
    voiceCharge: toState(paymentLink?.available ?? false, paymentLink?.missing_requirements ?? []),
    appleTap: toState(apple?.available ?? false, apple?.missing_requirements ?? [], { planned: true }),
    softpos: toState(softpos?.available ?? false, softpos?.missing_requirements ?? [], { planned: true }),
  };

  const default_rails: Partial<Record<string, ProcessingRail>> = {
    payment_link: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'payment_link' }).rail,
    nfc_tap: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'nfc_tap' }).rail,
    cash: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'cash' }).rail,
    store_credit: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'store_credit' }).rail,
    softpos: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'softpos' }).rail,
    apple_tap: selectProcessingRail({ merchantId: id, currency, country, captureMethod: 'apple_tap' }).rail,
  };

  const terminals = await listPaymentTerminals(admin, id, { includeSynthetic: true });

  return {
    ok: true,
    data: {
      merchant_id: id,
      country,
      currency,
      capabilities,
      flags: flagsFromMap(capabilities),
      default_rails,
      terminals,
      registry,
    },
  };
}

/** Resolve marketplace cart lines grouped by merchant (multi-vendor checkout). */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { feePlanFromMerchant } from './feePlan.ts';
import { type CartLine, cartLabel } from './cartItems.ts';

export type VendorCartBucket = {
  merchantId: string;
  businessName: string;
  paystackSubaccount: string;
  merchantPlan: string | null;
  platformFeePercent: number | null;
  platformFeeCap: number | null;
  items: CartLine[];
  subtotal: number;
};

export async function resolveMultiVendorCart(
  admin: SupabaseClient,
  cartItems: unknown,
): Promise<{ vendors: VendorCartBucket[]; total: number; currency: string } | { error: string }> {
  const raw = Array.isArray(cartItems) ? cartItems : [];
  if (!raw.length) return { error: 'cart_items is empty' };

  type PendingLine = { productId: string; variantId: string | null; qty: number };
  const pending: PendingLine[] = [];
  for (const row of raw) {
    const rec = row as Record<string, unknown>;
    const productId = String(rec.product_id ?? '').trim();
    const variantId = String(rec.variant_id ?? rec.variantId ?? '').trim() || null;
    const qty = Math.max(1, Math.min(99, Number(rec.quantity ?? rec.qty) || 1));
    if (!productId) return { error: 'cart item missing product_id' };
    pending.push({ productId, variantId, qty });
  }

  const productIds = [...new Set(pending.map((p) => p.productId))];
  const { data: products, error: prodErr } = await admin
    .from('products')
    .select('id, name, price, merchant_id, billing_type, track_inventory, stock_quantity, currency')
    .in('id', productIds);
  if (prodErr) return { error: prodErr.message || 'Could not load products' };

  const productMap = new Map((products ?? []).map((p) => [p.id as string, p]));
  const merchantIds = [...new Set((products ?? []).map((p) => p.merchant_id as string))];

  const { data: merchants, error: merchErr } = await admin
    .from('merchants')
    .select('id, business_name, status, paystack_subaccount, paystack_split_code, merchant_plan, subscription_status, platform_fee_percent, platform_fee_cap')
    .in('id', merchantIds);
  if (merchErr) return { error: merchErr.message || 'Could not load merchants' };

  const merchantMap = new Map((merchants ?? []).map((m) => [m.id as string, m]));
  const buckets = new Map<string, VendorCartBucket>();
  let currency = 'ZAR';

  for (const line of pending) {
    const p = productMap.get(line.productId);
    if (!p) return { error: 'A product in your cart is no longer available' };
    if (p.billing_type === 'subscription') {
      return { error: 'Subscription products must be purchased separately' };
    }

    const merchantId = String(p.merchant_id);
    const merchant = merchantMap.get(merchantId);
    if (!merchant || merchant.status !== 'approved') {
      return { error: 'A seller in your cart is not available for checkout' };
    }

    const routeCode = String(merchant.paystack_split_code || merchant.paystack_subaccount || '').trim();
    if (!routeCode.startsWith('ACCT_') && !routeCode.startsWith('SPL_')) {
      return { error: `${merchant.business_name} is not ready to receive marketplace payments yet` };
    }
    if (routeCode.startsWith('SPL_')) {
      return { error: `${merchant.business_name} uses legacy split routing — contact support for multi-seller checkout` };
    }

    let unitPrice = Number(p.price);
    let variantLabel: string | null = null;
    if (line.variantId) {
      const { data: variant } = await admin
        .from('product_variants')
        .select('id, label, price, stock_quantity, active')
        .eq('id', line.variantId)
        .eq('product_id', line.productId)
        .maybeSingle();
      if (!variant || !variant.active) return { error: 'A selected size/variant is no longer available' };
      unitPrice = Number(variant.price ?? p.price);
      variantLabel = variant.label;
      if (variant.stock_quantity != null && Number(variant.stock_quantity) < line.qty) {
        return { error: `${p.name} (${variant.label}) is out of stock` };
      }
    } else if (p.track_inventory && Number(p.stock_quantity || 0) < line.qty) {
      return { error: `${p.name} is out of stock` };
    }

    currency = String(p.currency || currency || 'ZAR');

    if (!buckets.has(merchantId)) {
      buckets.set(merchantId, {
        merchantId,
        businessName: String(merchant.business_name ?? 'Seller'),
        paystackSubaccount: routeCode,
        merchantPlan: feePlanFromMerchant(merchant),
        platformFeePercent: merchant.platform_fee_percent != null ? Number(merchant.platform_fee_percent) : null,
        platformFeeCap: merchant.platform_fee_cap != null ? Number(merchant.platform_fee_cap) : null,
        items: [],
        subtotal: 0,
      });
    }

    const bucket = buckets.get(merchantId)!;
    bucket.items.push({
      product_id: p.id as string,
      name: p.name as string,
      price: unitPrice,
      quantity: line.qty,
      ...(line.variantId ? { variant_id: line.variantId, variant_label: variantLabel ?? undefined } : {}),
    });
    bucket.subtotal += unitPrice * line.qty;
  }

  const vendors = [...buckets.values()];
  if (vendors.length < 2) {
    return { error: 'Multi-seller checkout requires items from at least two sellers' };
  }

  const total = vendors.reduce((n, v) => n + v.subtotal, 0);
  if (!(total > 0)) return { error: 'cart total must be greater than zero' };

  return { vendors, total, currency };
}

export function marketplaceCartLabel(vendors: VendorCartBucket[]): string {
  const lines = vendors.flatMap((v) => v.items);
  return cartLabel(lines);
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { markAbandonedCartRecovered } from './abandonedCart.ts';
import { createOrderFromPayment } from './orderCreate.ts';
import { persistTransactionLineItems, type LineItemInput } from './transactionLineItems.ts';
import type { VendorCartBucket } from './resolveMultiVendorCart.ts';

export type MarketplacePricing = {
  plan: string;
  percent: number;
  cap: number | null;
  feeSub: number;
  feeMajor: number;
  merchantShareMajor: number;
  merchantShareSub: number;
};

export function computeVendorPricing(
  subtotalMajor: number,
  toSubunits: (n: number) => number,
  computePricing: (input: {
    amountSub: number;
    plan?: string | null;
    customPercent?: number | null;
    capMajor?: number | null;
  }) => { plan: string; percent: number; cap: number | null; feeSub: number },
  vendor: VendorCartBucket,
): MarketplacePricing {
  const amountSub = toSubunits(subtotalMajor);
  const pricing = computePricing({
    amountSub,
    plan: vendor.merchantPlan,
    customPercent: vendor.platformFeePercent,
    capMajor: vendor.platformFeeCap,
  });
  const merchantShareSub = Math.max(0, amountSub - pricing.feeSub);
  return {
    plan: pricing.plan,
    percent: pricing.percent,
    cap: pricing.cap,
    feeSub: pricing.feeSub,
    feeMajor: pricing.feeSub / 100,
    merchantShareMajor: merchantShareSub / 100,
    merchantShareSub,
  };
}

export function buildPaystackFlatSplit(
  vendors: Array<{ paystackSubaccount: string; merchantShareSub: number }>,
): Record<string, unknown> {
  return {
    type: 'flat',
    bearer_type: 'account',
    subaccounts: vendors.map((v) => ({
      subaccount: v.paystackSubaccount,
      share: v.merchantShareSub,
    })),
  };
}

export async function fanOutMarketplaceCheckoutSuccess(
  admin: SupabaseClient,
  input: {
    reference: string;
    buyerEmail: string;
    buyerPhone?: string | null;
    currency: string;
    parentTransactionId?: string | null;
  },
): Promise<{ ok: boolean; orderNumbers?: string[]; message?: string }> {
  const { data: checkout } = await admin
    .from('marketplace_checkouts')
    .select('id, status, buyer_email, currency, total_amount')
    .eq('reference', input.reference)
    .maybeSingle();

  if (!checkout?.id) return { ok: false, message: 'marketplace checkout not found' };

  if (checkout.status === 'paid') {
    const { data: existingOrders } = await admin
      .from('buyer_orders')
      .select('order_number')
      .eq('marketplace_checkout_id', checkout.id);
    return { ok: true, orderNumbers: (existingOrders ?? []).map((o) => o.order_number as string) };
  }

  const { data: vendorRows } = await admin
    .from('marketplace_checkout_vendors')
    .select('*')
    .eq('checkout_id', checkout.id)
    .order('created_at', { ascending: true });

  if (!vendorRows?.length) return { ok: false, message: 'no vendor rows' };

  const orderNumbers: string[] = [];

  for (const row of vendorRows) {
    const merchantId = String(row.merchant_id);
    const cartJson = JSON.stringify(row.cart_items_json ?? []);
    const items = (row.cart_items_json ?? []) as Array<{ name: string; quantity: number }>;
    const label = items.length === 1
      ? (items[0].quantity > 1 ? `${items[0].name} × ${items[0].quantity}` : items[0].name)
      : `${items.length} items`;

    const order = await createOrderFromPayment(admin, {
      reference: input.reference,
      merchantId,
      amount: Number(row.subtotal),
      currency: input.currency || checkout.currency || 'ZAR',
      buyerEmail: input.buyerEmail,
      buyerPhone: input.buyerPhone,
      label,
      purchaseType: 'marketplace_cart',
      cartItemsJson: cartJson,
      marketplaceCheckoutId: checkout.id,
    });

    if (order.ok && order.order_number) {
      orderNumbers.push(order.order_number);
      const { data: orderRow } = await admin
        .from('buyer_orders')
        .select('id')
        .eq('marketplace_checkout_id', checkout.id)
        .eq('merchant_id', merchantId)
        .maybeSingle();

      await admin.from('marketplace_checkout_vendors').update({
        buyer_order_id: orderRow?.id ?? null,
      }).eq('id', row.id);

      await admin.rpc('award_loyalty_points', {
        p_merchant_id: merchantId,
        p_buyer_email: input.buyerEmail.toLowerCase(),
        p_amount: Number(row.subtotal),
        p_reference: `${input.reference}:${merchantId}`,
      }).then(() => {}, () => {});

      await markAbandonedCartRecovered(admin, merchantId, input.buyerEmail);
    }
  }

  if (input.parentTransactionId) {
    const allLines: LineItemInput[] = [];
    for (const row of vendorRows) {
      const merchantId = String(row.merchant_id);
      const vendorLines = (row.cart_items_json as Array<Record<string, unknown>> ?? []).map((item, idx) => {
        const qty = Math.max(1, Number(item.quantity) || 1);
        const unit = Number(item.price) || 0;
        return {
          product_id: String(item.product_id ?? ''),
          name: String(item.name ?? 'Item'),
          quantity: qty,
          unit_price: unit,
          line_total: Math.round(unit * qty * 100) / 100,
          variant_label: item.variant_label ? String(item.variant_label) : null,
          meta: { sort_order: idx, marketplace_checkout_id: checkout.id, merchant_id: merchantId },
        };
      });
      allLines.push(...vendorLines);
    }
    // Line items + inventory are owned by payment.recorded → Inventory Consumer.
    // Fan-out only mirrors lines onto the parent txn when the consumer has not yet
    // (idempotent persist). Never call apply_inventory_from_transaction here.
    if (allLines.length) {
      await persistTransactionLineItems(admin, {
        transactionId: input.parentTransactionId,
        reference: input.reference,
        lines: allLines,
      });
    }
  }

  await admin.from('marketplace_checkouts').update({
    status: 'paid',
    updated_at: new Date().toISOString(),
  }).eq('id', checkout.id);

  await admin.rpc('try_qualify_founding_and_referrals', {
    p_merchant_id: vendorRows[0].merchant_id,
  }).then(() => {}, () => {});

  return { ok: true, orderNumbers };
}

/** Store credit redemption at checkout — ledger-only, Paystack for card remainder. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type StoreCreditRow = {
  id: string;
  balance_remaining: number;
  currency: string;
  code: string;
};

export async function resolveStoreCreditForCheckout(
  admin: SupabaseClient,
  creditId: string,
  merchantId: string,
  buyerEmail: string,
): Promise<{ ok: true; credit: StoreCreditRow } | { ok: false; message: string }> {
  const email = buyerEmail.trim().toLowerCase();
  if (!creditId || !email.includes('@')) {
    return { ok: false, message: 'Store credit not available' };
  }

  await admin.rpc('_expire_store_credits').then(() => {}, () => {});

  const { data: row, error } = await admin
    .from('merchant_store_credits')
    .select('id, balance_remaining, currency, code, buyer_email, status, expires_at')
    .eq('id', creditId)
    .eq('merchant_id', merchantId)
    .maybeSingle();

  if (error || !row) {
    return { ok: false, message: 'Store credit not found' };
  }
  if (String(row.buyer_email).toLowerCase() !== email) {
    return { ok: false, message: 'Store credit does not match this email' };
  }
  if (row.status !== 'active' || Number(row.balance_remaining) <= 0) {
    return { ok: false, message: 'Store credit is no longer available' };
  }
  if (row.expires_at && new Date(String(row.expires_at)) < new Date()) {
    return { ok: false, message: 'Store credit has expired' };
  }

  return {
    ok: true,
    credit: {
      id: String(row.id),
      balance_remaining: Number(row.balance_remaining),
      currency: String(row.currency || 'ZAR'),
      code: String(row.code),
    },
  };
}

export function splitStoreCreditAmount(orderAmount: number, creditBalance: number): {
  storeCreditApplied: number;
  cardAmount: number;
} {
  const applied = Math.min(Math.max(creditBalance, 0), Math.max(orderAmount, 0));
  const card = Math.round((orderAmount - applied) * 100) / 100;
  return { storeCreditApplied: applied, cardAmount: card > 0 ? card : 0 };
}

export async function redeemStoreCreditIfNeeded(
  admin: SupabaseClient,
  opts: {
    creditId: string | null;
    merchantId: string;
    buyerEmail: string;
    amount: number;
    reference: string;
    transactionId?: string | null;
  },
): Promise<{ ok: boolean; message?: string }> {
  const { creditId, merchantId, buyerEmail, amount, reference, transactionId } = opts;
  if (!creditId || amount <= 0) return { ok: true };

  const { data, error } = await admin.rpc('store_credit_redeem', {
    p_credit_id: creditId,
    p_merchant_id: merchantId,
    p_buyer_email: buyerEmail,
    p_amount: amount,
    p_reference: reference,
    p_transaction_id: transactionId ?? null,
  });

  if (error) {
    console.error('store_credit_redeem failed', error);
    return { ok: false, message: error.message || 'Could not apply store credit' };
  }
  if (!data?.ok) {
    return { ok: false, message: String(data?.error || 'Could not apply store credit') };
  }
  return { ok: true };
}

/** Invoice deposit / balance checkout amounts. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type InvoicePaymentKind = 'deposit' | 'balance' | 'full';

export type ResolvedInvoiceCheckout = {
  ok: boolean;
  error?: string;
  invoice_id?: string;
  merchant_id?: string;
  payment_kind?: InvoicePaymentKind;
  amount?: number;
  currency?: string;
  total?: number;
  amount_paid?: number;
  balance_due?: number;
  deposit_percent?: number | null;
  deposit_amount?: number | null;
  invoice_number?: string;
  label?: string;
};

export async function resolveInvoiceCheckout(
  admin: SupabaseClient,
  invoiceId: string,
  paymentKind: InvoicePaymentKind = 'full',
): Promise<ResolvedInvoiceCheckout> {
  const { data, error } = await admin.rpc('resolve_invoice_checkout', {
    p_invoice_id: invoiceId,
    p_payment_kind: paymentKind,
  });
  if (error) return { ok: false, error: error.message };
  return (data ?? { ok: false, error: 'unknown' }) as ResolvedInvoiceCheckout;
}

export async function applyInvoicePayment(
  admin: SupabaseClient,
  invoiceId: string,
  paidAmount: number,
  reference: string,
  paymentKind: InvoicePaymentKind,
): Promise<void> {
  const { data: inv } = await admin
    .from('merchant_invoices')
    .select('id, total, amount_paid, deposit_percent, status')
    .eq('id', invoiceId)
    .maybeSingle();
  if (!inv) return;

  const newPaid = Number(inv.amount_paid ?? 0) + paidAmount;
  const total = Number(inv.total ?? 0);
  const fullyPaid = newPaid >= total - 0.009;

  const patch: Record<string, unknown> = {
    amount_paid: newPaid,
    paystack_reference: reference,
    updated_at: new Date().toISOString(),
  };

  if (paymentKind === 'deposit' && !inv.deposit_paid_at) {
    patch.deposit_paid_at = new Date().toISOString();
  }

  if (fullyPaid) {
    patch.status = 'paid';
    patch.paid_at = new Date().toISOString();
  } else if (newPaid > 0) {
    patch.status = 'partial';
  }

  await admin.from('merchant_invoices').update(patch).eq('id', invoiceId);
}

/** RedFace Core Payment Engine — idempotency for all money-moving operations. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type PaymentRequestType =
  | 'payment_session'
  | 'checkout'
  | 'refund'
  | 'refund_process'
  | 'quote_accept'
  | 'table_pay'
  | 'subscription'
  | 'store_credit';

export type PaymentRequestRow = {
  id: string;
  idempotency_key: string;
  merchant_id: string;
  request_type: string;
  status: string;
  customer_email: string | null;
  payment_session_id: string | null;
  transaction_reference: string | null;
  amount: number | null;
  currency: string | null;
  request_payload: Record<string, unknown>;
  response_payload: Record<string, unknown>;
  retry_count: number;
  created_at: string;
  updated_at: string;
  completed_at: string | null;
};

export type CheckoutIdentity = {
  reference: string;
  idempotencyKey: string;
  reused: boolean;
  alreadyPaid: boolean;
  retryCount: number;
  cachedResponse: Record<string, unknown> | null;
};

export function readIdempotencyKey(req: Request, body: Record<string, unknown>): string | null {
  const header = req.headers.get('Idempotency-Key')?.trim()
    || req.headers.get('X-Idempotency-Key')?.trim()
    || '';
  const bodyKey = String(body.idempotency_key ?? '').trim();
  return header || bodyKey || null;
}

export function ensureIdempotencyKey(existing: string | null | undefined): string {
  if (existing?.trim()) return existing.trim();
  return `rf_${crypto.randomUUID()}`;
}

export async function claimPaymentRequest(
  admin: SupabaseClient,
  opts: {
    merchantId: string;
    idempotencyKey: string;
    requestType: PaymentRequestType;
    customerEmail?: string | null;
    amount?: number | null;
    currency?: string | null;
    requestPayload?: Record<string, unknown>;
  },
): Promise<
  | { ok: true; created: boolean; retryCount: number; request: PaymentRequestRow }
  | { ok: false; error: string }
> {
  const { data, error } = await admin.rpc('claim_payment_request', {
    p_merchant_id: opts.merchantId,
    p_idempotency_key: opts.idempotencyKey,
    p_request_type: opts.requestType,
    p_customer_email: opts.customerEmail ?? null,
    p_amount: opts.amount ?? null,
    p_currency: opts.currency ?? null,
    p_request_payload: opts.requestPayload ?? {},
  });
  if (error) return { ok: false, error: error.message };
  const payload = data as {
    ok?: boolean;
    error?: string;
    created?: boolean;
    retry_count?: number;
    request?: PaymentRequestRow;
  };
  if (!payload?.ok || !payload.request) {
    return { ok: false, error: payload?.error ?? 'claim_failed' };
  }
  return {
    ok: true,
    created: !!payload.created,
    retryCount: Number(payload.retry_count ?? 0),
    request: payload.request,
  };
}

export async function completePaymentRequest(
  admin: SupabaseClient,
  opts: {
    merchantId: string;
    idempotencyKey: string;
    requestType: PaymentRequestType;
    status?: 'pending' | 'processing' | 'completed' | 'failed';
    paymentSessionId?: string | null;
    transactionReference?: string | null;
    responsePayload?: Record<string, unknown>;
  },
): Promise<void> {
  await admin.rpc('complete_payment_request', {
    p_merchant_id: opts.merchantId,
    p_idempotency_key: opts.idempotencyKey,
    p_request_type: opts.requestType,
    p_status: opts.status ?? 'completed',
    p_payment_session_id: opts.paymentSessionId ?? null,
    p_transaction_reference: opts.transactionReference ?? null,
    p_response_payload: opts.responsePayload ?? {},
  });
}

export async function getPaymentRequest(
  admin: SupabaseClient,
  merchantId: string,
  idempotencyKey: string,
  requestType?: PaymentRequestType,
): Promise<PaymentRequestRow | null> {
  const { data } = await admin.rpc('get_payment_request_by_idempotency', {
    p_merchant_id: merchantId,
    p_idempotency_key: idempotencyKey,
    p_request_type: requestType ?? null,
  });
  if (!data || typeof data !== 'object') return null;
  return data as PaymentRequestRow;
}

export async function resolveCheckoutIdentity(
  admin: SupabaseClient,
  req: Request,
  body: Record<string, unknown>,
  merchantId: string,
): Promise<CheckoutIdentity> {
  const idempotencyKey = ensureIdempotencyKey(readIdempotencyKey(req, body));

  const existingRequest = await getPaymentRequest(admin, merchantId, idempotencyKey, 'checkout');
  if (existingRequest?.status === 'completed' && existingRequest.response_payload) {
    const cached = existingRequest.response_payload;
    if (cached.already_paid || cached.authorization_url) {
      return {
        reference: String(existingRequest.transaction_reference ?? cached.reference ?? ''),
        idempotencyKey,
        reused: true,
        alreadyPaid: !!cached.already_paid,
        retryCount: existingRequest.retry_count,
        cachedResponse: cached,
      };
    }
  }

  const { data: existingRef } = await admin.rpc('get_payment_reference_by_idempotency', {
    p_key: idempotencyKey,
  });

  if (existingRef) {
    const { data: txn } = await admin
      .from('transactions')
      .select('status, reference')
      .eq('reference', existingRef)
      .maybeSingle();
    if (txn?.status === 'success') {
      await claimPaymentRequest(admin, {
        merchantId,
        idempotencyKey,
        requestType: 'checkout',
        customerEmail: String(body.email ?? '').trim() || null,
      });
      return {
        reference: String(existingRef),
        idempotencyKey,
        reused: true,
        alreadyPaid: true,
        retryCount: (existingRequest?.retry_count ?? 0) + 1,
        cachedResponse: { already_paid: true, reference: existingRef },
      };
    }
    if (txn?.status === 'pending') {
      const claim = await claimPaymentRequest(admin, {
        merchantId,
        idempotencyKey,
        requestType: 'checkout',
        customerEmail: String(body.email ?? '').trim() || null,
        amount: body.amount != null ? Number(body.amount) : null,
        currency: String(body.currency ?? 'ZAR'),
        requestPayload: { source: 'init_payment' },
      });
      return {
        reference: String(existingRef),
        idempotencyKey,
        reused: true,
        alreadyPaid: false,
        retryCount: claim.ok ? claim.retryCount : 0,
        cachedResponse: existingRequest?.response_payload ?? null,
      };
    }
  }

  await claimPaymentRequest(admin, {
    merchantId,
    idempotencyKey,
    requestType: 'checkout',
    customerEmail: String(body.email ?? '').trim() || null,
    amount: body.amount != null ? Number(body.amount) : null,
    currency: String(body.currency ?? 'ZAR'),
    requestPayload: { source: 'init_payment' },
  });

  return {
    reference: `rfp_${Date.now()}_${crypto.randomUUID().slice(0, 8)}`,
    idempotencyKey,
    reused: false,
    alreadyPaid: false,
    retryCount: 0,
    cachedResponse: null,
  };
}

export function idempotentSessionMessage(status: string): string | null {
  switch (status) {
    case 'waiting':
    case 'opened':
    case 'processing':
      return 'Payment already started. Waiting for customer…';
    case 'paid':
      return 'Payment already received.';
    case 'expired':
      return 'Previous payment session expired.';
    case 'cancelled':
      return 'Previous payment session was cancelled.';
    default:
      return null;
  }
}

/** Return cached response when an idempotent request already completed. */
export async function tryResumeCompletedRequest(
  admin: SupabaseClient,
  merchantId: string,
  idempotencyKey: string,
  requestType: PaymentRequestType,
  requestPayload?: Record<string, unknown>,
): Promise<
  | { hit: true; payload: Record<string, unknown>; retryCount: number }
  | { hit: false; retryCount: number }
> {
  const claim = await claimPaymentRequest(admin, {
    merchantId,
    idempotencyKey,
    requestType,
    requestPayload,
  });
  if (!claim.ok) return { hit: false, retryCount: 0 };

  const payload = claim.request.response_payload ?? {};
  const hasPayload = Object.keys(payload).length > 0;
  if (!claim.created && claim.request.status === 'completed' && hasPayload) {
    return { hit: true, payload, retryCount: claim.retryCount };
  }
  return { hit: false, retryCount: claim.retryCount };
}

import { createClient, type SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { checkAiCredits, PREMIUM_AI_ACTIONS } from './aiSubscription.ts';

export async function requireUser(admin: SupabaseClient, req: Request): Promise<string | null> {
  const token = (req.headers.get('Authorization') ?? '').replace(/^Bearer\s+/i, '').trim();
  if (!token) return null;
  const { data, error } = await admin.auth.getUser(token);
  if (error || !data?.user?.email) return null;
  return data.user.email.toLowerCase();
}

export async function requireMerchantById(
  admin: SupabaseClient,
  req: Request,
  merchantId: string,
) {
  const email = await requireUser(admin, req);
  if (!email) return null;

  const { data: merchant } = await admin
    .from('merchants')
    .select('id, business_name, country, category, email, subscription_plan, merchant_plan, subscription_status, ai_credits, ai_credits_used, ai_credits_reset_at')
    .eq('id', merchantId)
    .ilike('email', email)
    .maybeSingle();
  if (merchant?.id === merchantId) return merchant;

  const { data: staffRow } = await admin
    .from('merchant_staff')
    .select('merchant_id')
    .ilike('email', email)
    .eq('status', 'active')
    .eq('merchant_id', merchantId)
    .maybeSingle();
  if (!staffRow) return null;

  const { data: staffMerchant } = await admin
    .from('merchants')
    .select('id, business_name, country, category, email, subscription_plan, merchant_plan, subscription_status, ai_credits, ai_credits_used, ai_credits_reset_at')
    .eq('id', merchantId)
    .maybeSingle();
  return staffMerchant?.id === merchantId ? staffMerchant : null;
}

async function resetCreditsIfDue(admin: SupabaseClient, merchantId: string) {
  const { error } = await admin.rpc('reset_merchant_ai_credits_if_due', { p_merchant_id: merchantId });
  if (error && error.code !== '42883') {
    console.warn('reset_merchant_ai_credits_if_due failed', error.message);
  }
}

export async function consumeAiCredit(
  admin: SupabaseClient,
  merchantId: string,
  action: string,
) {
  if (!PREMIUM_AI_ACTIONS.has(action)) {
    return { ok: true as const, credits_remaining: 999 };
  }

  await resetCreditsIfDue(admin, merchantId);
  const { data: row } = await admin
    .from('merchants')
    .select('subscription_plan, merchant_plan, subscription_status, ai_credits, ai_credits_used')
    .eq('id', merchantId)
    .maybeSingle();
  if (!row) return { ok: false as const, status: 404, body: { error: 'Merchant not found.' } };

  const gate = checkAiCredits(row, action);
  if (!gate.ok) {
    return {
      ok: false as const,
      status: gate.code === 'PREMIUM_REQUIRED' ? 402 : 429,
      body: {
        error: gate.message,
        code: gate.code,
        credits_remaining: gate.credits_remaining,
        credits_limit: gate.credits_limit,
      },
    };
  }

  await admin
    .from('merchants')
    .update({ ai_credits_used: Number(row.ai_credits_used ?? 0) + 1 })
    .eq('id', merchantId);

  return {
    ok: true as const,
    credits_remaining: Math.max(0, gate.credits_remaining - 1),
  };
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type DvaCountry = { code: 'NG' | 'GH'; currency: string };

export function dvaEligibleCountry(country: string | null | undefined): DvaCountry | null {
  const c = String(country ?? '').trim().toLowerCase();
  if (c === 'nigeria' || c === 'ng') return { code: 'NG', currency: 'NGN' };
  if (c === 'ghana' || c === 'gh') return { code: 'GH', currency: 'GHS' };
  return null;
}

export function splitMerchantContactName(businessName: string): { firstName: string; lastName: string } {
  const parts = String(businessName ?? '').trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return { firstName: 'Merchant', lastName: 'Account' };
  if (parts.length === 1) return { firstName: parts[0], lastName: 'Business' };
  return { firstName: parts[0], lastName: parts.slice(1).join(' ') };
}

export type PaystackDvaPayload = Record<string, unknown>;

export async function upsertMerchantDedicatedAccount(
  admin: SupabaseClient,
  merchantId: string,
  dvaData: PaystackDvaPayload,
  patch: { status?: string; error_message?: string | null } = {},
): Promise<void> {
  const bank = (dvaData.bank ?? {}) as Record<string, unknown>;
  const customer = (dvaData.customer ?? {}) as Record<string, unknown>;
  const countryCode = String(dvaData.currency ?? 'NGN').toUpperCase() === 'GHS' ? 'GH' : 'NG';
  const active = dvaData.active === true || dvaData.active === 1 || dvaData.assigned === true;

  await admin.from('merchant_dedicated_accounts').upsert({
    merchant_id: merchantId,
    status: patch.status ?? (active ? 'active' : 'pending'),
    country_code: countryCode,
    currency: String(dvaData.currency ?? (countryCode === 'GH' ? 'GHS' : 'NGN')).toUpperCase(),
    paystack_customer_code: customer.customer_code ? String(customer.customer_code) : null,
    paystack_dva_id: dvaData.id != null ? String(dvaData.id) : null,
    account_number: dvaData.account_number ? String(dvaData.account_number) : null,
    account_name: dvaData.account_name ? String(dvaData.account_name) : null,
    bank_name: bank.name ? String(bank.name) : null,
    bank_slug: bank.slug ? String(bank.slug) : null,
    is_active: active,
    error_message: patch.error_message ?? null,
    meta: dvaData,
    updated_at: new Date().toISOString(),
  }, { onConflict: 'merchant_id' });
}

export async function resolveMerchantFromDedicatedAccountNumber(
  admin: SupabaseClient,
  accountNumber: string,
): Promise<string | null> {
  const num = String(accountNumber ?? '').trim();
  if (!num) return null;
  const { data } = await admin
    .from('merchant_dedicated_accounts')
    .select('merchant_id')
    .eq('account_number', num)
    .eq('is_active', true)
    .maybeSingle();
  return (data?.merchant_id as string) ?? null;
}

export async function resolveMerchantIdForDvaWebhook(
  admin: SupabaseClient,
  data: Record<string, unknown>,
): Promise<string | null> {
  const dva = (data.dedicated_account ?? data) as PaystackDvaPayload;
  const accountNumber = String(dva.account_number ?? '').trim();
  if (accountNumber) {
    const byNumber = await resolveMerchantFromDedicatedAccountNumber(admin, accountNumber);
    if (byNumber) return byNumber;
  }

  const customer = (data.customer ?? dva.customer ?? {}) as Record<string, unknown>;
  const email = String(customer.email ?? '').trim().toLowerCase();
  if (email) {
    const { data: merchant } = await admin
      .from('merchants')
      .select('id')
      .ilike('email', email)
      .eq('status', 'approved')
      .maybeSingle();
    if (merchant?.id) return String(merchant.id);
  }

  const customerCode = String(customer.customer_code ?? '').trim();
  if (customerCode) {
    const { data: row } = await admin
      .from('merchant_dedicated_accounts')
      .select('merchant_id')
      .eq('paystack_customer_code', customerCode)
      .maybeSingle();
    if (row?.merchant_id) return String(row.merchant_id);
  }

  return null;
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type CryptoAsset = 'btc' | 'eth' | 'usdt_trc20' | 'usdt_erc20';

export const CRYPTO_ASSETS: Record<
  CryptoAsset,
  { coingeckoId: string; label: string; decimals: number; network: string }
> = {
  btc: { coingeckoId: 'bitcoin', label: 'Bitcoin (BTC)', decimals: 8, network: 'Bitcoin' },
  eth: { coingeckoId: 'ethereum', label: 'Ethereum (ETH)', decimals: 6, network: 'Ethereum' },
  usdt_trc20: { coingeckoId: 'tether', label: 'USDT (TRC-20)', decimals: 2, network: 'TRON' },
  usdt_erc20: { coingeckoId: 'tether', label: 'USDT (ERC-20)', decimals: 2, network: 'Ethereum' },
};

type CryptoSettingsRow = {
  merchant_id: string;
  enabled: boolean;
  btc_address: string | null;
  eth_address: string | null;
  usdt_trc20_address: string | null;
  usdt_erc20_address: string | null;
  default_asset: CryptoAsset;
  instructions: string | null;
};

export function walletForAsset(settings: CryptoSettingsRow, asset: CryptoAsset): string | null {
  const map: Record<CryptoAsset, string | null> = {
    btc: settings.btc_address,
    eth: settings.eth_address,
    usdt_trc20: settings.usdt_trc20_address,
    usdt_erc20: settings.usdt_erc20_address,
  };
  const addr = map[asset];
  return addr && addr.trim() ? addr.trim() : null;
}

export async function fetchCryptoFiatRate(asset: CryptoAsset, fiat: string): Promise<number | null> {
  const meta = CRYPTO_ASSETS[asset];
  if (!meta) return null;
  const vs = fiat.toLowerCase() === 'zar' ? 'zar' : fiat.toLowerCase();
  const url = `https://api.coingecko.com/api/v3/simple/price?ids=${meta.coingeckoId}&vs_currencies=${vs}`;
  const res = await fetch(url, { headers: { Accept: 'application/json' } });
  if (!res.ok) return null;
  const data = await res.json() as Record<string, Record<string, number>>;
  const rate = data[meta.coingeckoId]?.[vs];
  return typeof rate === 'number' && rate > 0 ? rate : null;
}

export function roundCryptoAmount(amount: number, decimals: number): number {
  const factor = 10 ** decimals;
  return Math.ceil(amount * factor) / factor;
}

export async function createCryptoPaymentRequest(
  admin: SupabaseClient,
  input: {
    merchantId: string;
    fiatAmount: number;
    fiatCurrency: string;
    asset: CryptoAsset;
    customerEmail?: string | null;
    customerNote?: string | null;
    paymentSessionId?: string | null;
    ttlMinutes?: number;
  },
): Promise<{ ok: true; request: Record<string, unknown> } | { ok: false; message: string }> {
  const { data: settings, error: settingsErr } = await admin
    .from('merchant_crypto_settings')
    .select('*')
    .eq('merchant_id', input.merchantId)
    .maybeSingle();

  if (settingsErr || !settings?.enabled) {
    return { ok: false, message: 'Crypto payments are not enabled for this merchant.' };
  }

  const asset = input.asset in CRYPTO_ASSETS ? input.asset : (settings.default_asset as CryptoAsset);
  const wallet = walletForAsset(settings as CryptoSettingsRow, asset);
  if (!wallet) {
    return { ok: false, message: `No wallet address configured for ${CRYPTO_ASSETS[asset].label}.` };
  }

  const fiatAmount = Math.round(Number(input.fiatAmount) * 100) / 100;
  if (!Number.isFinite(fiatAmount) || fiatAmount <= 0) {
    return { ok: false, message: 'Enter a valid amount.' };
  }

  const fiatCurrency = String(input.fiatCurrency || 'ZAR').toUpperCase();
  const rate = await fetchCryptoFiatRate(asset, fiatCurrency);
  if (!rate) {
    return { ok: false, message: 'Could not fetch live crypto rate. Try again in a moment.' };
  }

  const cryptoAmount = roundCryptoAmount(fiatAmount / rate, CRYPTO_ASSETS[asset].decimals);
  const reference = `RFC-${input.merchantId.slice(0, 4).toUpperCase()}-${crypto.randomUUID().slice(0, 8).toUpperCase()}`;
  const ttl = Math.min(Math.max(Number(input.ttlMinutes) || 60, 15), 24 * 60);
  const expiresAt = new Date(Date.now() + ttl * 60_000).toISOString();

  const { data: row, error } = await admin
    .from('crypto_payment_requests')
    .insert({
      merchant_id: input.merchantId,
      reference,
      fiat_amount: fiatAmount,
      fiat_currency: fiatCurrency,
      asset,
      crypto_amount: cryptoAmount,
      crypto_rate: rate,
      wallet_address: wallet,
      customer_email: input.customerEmail?.trim() || null,
      customer_note: input.customerNote?.trim() || null,
      payment_session_id: input.paymentSessionId || null,
      expires_at: expiresAt,
    })
    .select('*')
    .single();

  if (error || !row) {
    return { ok: false, message: error?.message || 'Could not create crypto payment request.' };
  }

  await admin.rpc('track_merchant_business_event', {
    p_merchant_id: input.merchantId,
    p_event_type: 'crypto_payment_requested',
    p_amount: fiatAmount,
    p_currency: fiatCurrency,
    p_session_id: reference,
    p_source: 'crypto',
    p_idempotency_key: `crypto_req:${reference}`,
    p_payload: { asset, crypto_amount: cryptoAmount, wallet_address: wallet },
  });

  return { ok: true, request: row as Record<string, unknown> };
}

