export type SoftposPartner = 'istore_tap' | 'yoco_tap' | 'stripe_terminal' | null;

export type RoutingContext = {
  merchantId: string;
  currency?: string | null;
  country?: string | null;
  captureMethod?: CaptureMethod | string | null;
  businessIntent?: string | null;
  /** When SoftPOS partner onboarding is complete, set the live partner id. */
  softposPartner?: SoftposPartner;
  /** Merchant entitled to Stripe Terminal SoftPOS (after Stripe confirms). */
  stripeTerminalEntitled?: boolean;
  /** Ops override — support tooling only. */
  forceRail?: ProcessingRail | null;
};

export type RoutingDecision = {
  rail: ProcessingRail;
  reason: string;
  /** True when a planned SoftPOS rail was preferred but is not live yet. */
  fallback?: boolean;
  plannedRail?: ProcessingRail | null;
  captureMethod: string;
  decidedAt: string;
};

const PAYSTACK_COUNTRIES = new Set(['ZA', 'NG', 'GH', 'KE']);

function normalizeCountry(country?: string | null): string {
  return String(country ?? 'ZA').trim().toUpperCase() || 'ZA';
}

function normalizeCurrency(currency?: string | null, country?: string): string {
  const c = String(currency ?? '').trim().toUpperCase();
  if (c) return c;
  if (country === 'NG') return 'NGN';
  if (country === 'GH') return 'GHS';
  if (country === 'KE') return 'KES';
  return 'ZAR';
}

function isSoftposCapture(capture: string): boolean {
  return capture === 'apple_tap' || capture === 'softpos' || capture === 'google_tap';
}

/**
 * Routing & Policy Engine v2.
 * Deterministic rules; SoftPOS partners register as planned until entitlement.
 * Provider health / cost / auth-rate signals arrive with the second live acquirer.
 */
export function selectProcessingRail(ctx: RoutingContext): RoutingDecision {
  const capture = String(ctx.captureMethod ?? '').trim().toLowerCase() || 'payment_link';
  const country = normalizeCountry(ctx.country);
  const currency = normalizeCurrency(ctx.currency, country);
  const decidedAt = new Date().toISOString();

  if (ctx.forceRail) {
    return {
      rail: ctx.forceRail,
      reason: `ops override → ${ctx.forceRail}`,
      captureMethod: capture,
      decidedAt,
    };
  }

  if (capture === 'cash') {
    return {
      rail: 'cash',
      reason: 'cash capture settles internally on the merchant ledger',
      captureMethod: capture,
      decidedAt,
    };
  }
  if (capture === 'store_credit') {
    return {
      rail: 'store_credit',
      reason: 'store credit settles against the merchant liability ledger',
      captureMethod: capture,
      decidedAt,
    };
  }

  // SoftPOS / Tap to Pay — capability; provider selected by country + entitlement.
  // Never assume Swiss Stripe platform ⇒ SoftPOS for ZA operating merchants.
  if (isSoftposCapture(capture)) {
    const saPartner =
      ctx.softposPartner === 'istore_tap' || ctx.softposPartner === 'yoco_tap'
        ? ctx.softposPartner
        : null;
    const stripeEntitled =
      Boolean(ctx.stripeTerminalEntitled) || ctx.softposPartner === 'stripe_terminal';
    const offer = resolveSoftposOffer({
      country,
      stripeTerminalEntitled: stripeEntitled,
      saPartner,
    });

    if (offer.offered && offer.providerId === 'istore_tap') {
      return {
        rail: 'istore_tap',
        reason: offer.reason,
        captureMethod: capture,
        decidedAt,
      };
    }
    if (offer.offered && offer.providerId === 'yoco_tap') {
      return {
        rail: 'yoco_tap',
        reason: offer.reason,
        captureMethod: capture,
        decidedAt,
      };
    }
    if (offer.offered && offer.providerId === 'stripe_terminal') {
      return {
        rail: 'stripe_terminal',
        reason: offer.reason,
        captureMethod: capture,
        decidedAt,
      };
    }

    const plannedRail: ProcessingRail | null =
      country === 'ZA'
        ? 'istore_tap'
        : isStripeTerminalTtpCountry(country)
          ? 'stripe_terminal'
          : null;

    // SoftPOS is not live — do not route in-person tap to Paystack SoftPOS.
    // Online SA capture still uses Paystack via link/QR/checkout actions.
    return {
      rail: PAYSTACK_COUNTRIES.has(country) ? 'paystack' : 'stripe',
      reason: offer.reason,
      fallback: true,
      plannedRail,
      captureMethod: capture,
      decidedAt,
    };
  }

  // Country-aware default acquiring (online / QR / links / checkout)
  if (PAYSTACK_COUNTRIES.has(country)) {
    return {
      rail: 'paystack',
      reason: `default SA/Africa online acquiring rail for ${country}/${currency}`,
      captureMethod: capture,
      decidedAt,
    };
  }

  // Non-Paystack countries: Stripe Checkout when configured, else Paystack fallback label.
  return {
    rail: 'stripe',
    reason: `international online rail for ${country}/${currency} (Stripe Checkout when active)`,
    captureMethod: capture,
    decidedAt,
  };
}

export function listActiveCapabilities(kind?: 'capture' | 'rail'): CapabilityDescriptor[] {
  return CAPABILITY_REGISTRY.filter(
    (c) => c.status === 'active' && (kind ? c.kind === kind : true),
  );
}

export function listPlannedCapabilities(kind?: 'capture' | 'rail'): CapabilityDescriptor[] {
  return CAPABILITY_REGISTRY.filter(
    (c) => c.status === 'planned' && (kind ? c.kind === kind : true),
  );
}

/** Serialize a routing decision for payment_sessions.metadata.routing */
export function routingDecisionToMeta(decision: RoutingDecision): Record<string, unknown> {
  return {
    rail: decision.rail,
    reason: decision.reason,
    capture_method: decision.captureMethod,
    decided_at: decision.decidedAt,
    ...(decision.fallback ? { fallback: true } : {}),
    ...(decision.plannedRail ? { planned_rail: decision.plannedRail } : {}),
  };
}

/**
 * Business modules consume Business Facts — not provider APIs (Invariant XI).
 *
 * Called once per newly committed ledger payment (`payment.recorded`).
 * Inventory runs as its own bounded context:
 *   payment.recorded → inventory.consume.requested → inventory.consumed
 * CRM and loyalty remain direct consumers until they follow the same pattern.
 * POS cash/walk-in sales without payment.recorded stay on their own path.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';
import { completePosSplitCardTender, posSaleIdFromMetadata } from './posSplitTender.ts';
import {
  isMarketplaceCheckout,
  resolveCheckoutMetadata,
  shouldSkipInventoryForPayment,
} from './transactionLineItems.ts';
import { requestAndConsumeInventory } from './consumeInventoryFromPayment.ts';
import { consumeCrmFromPaymentRecorded } from './consumeCrmFromPayment.ts';
import { consumeLoyaltyFromPaymentRecorded } from './consumeLoyaltyFromPayment.ts';
import { consumeReviewLifecycleFromPaymentRecorded } from './consumeReviewLifecycleFromPayment.ts';

export type PaymentRecordedContext = {
  reference: string;
  merchantId?: string | null;
  amount?: number | null;
  currency?: string | null;
  businessIntent?: string | null;
  processingRail?: string | null;
  txnKey?: string | null;
  correlationId?: string | null;
  causationId?: string | null;
};

export async function consumePaymentRecorded(
  admin: SupabaseClient,
  ctx: PaymentRecordedContext,
): Promise<{ ok: boolean; skipped?: boolean; error?: string }> {
  const reference = String(ctx.reference ?? '').trim();
  if (!reference) return { ok: false, error: 'reference_required' };

  const { data: txn, error: txnErr } = await admin
    .from('transactions')
    .select('id, merchant_id, amount, currency, buyer_email, payment_session_id, status')
    .eq('reference', reference)
    .maybeSingle();
  if (txnErr || !txn) return { ok: false, error: txnErr?.message ?? 'transaction_not_found' };
  if (txn.status !== 'success') return { ok: true, skipped: true };

  let sessionMeta: Record<string, unknown> = {};
  let captureMethod: string | null = null;
  let businessIntent = ctx.businessIntent ?? null;

  if (txn.payment_session_id) {
    const { data: sess } = await admin
      .from('payment_sessions')
      .select('metadata, business_intent, capture_method, processing_rail')
      .eq('id', txn.payment_session_id)
      .maybeSingle();
    if (sess) {
      sessionMeta = (sess.metadata && typeof sess.metadata === 'object')
        ? sess.metadata as Record<string, unknown>
        : {};
      captureMethod = sess.capture_method ?? null;
      businessIntent = businessIntent ?? sess.business_intent ?? null;
    }
  }

  const posSaleId = posSaleIdFromMetadata(sessionMeta);
  const merchantId = String(ctx.merchantId ?? txn.merchant_id ?? '');
  if (!merchantId) return { ok: false, error: 'merchant_id_required' };

  if (posSaleId) {
    const splitDone = await completePosSplitCardTender(
      admin,
      posSaleId,
      reference,
      txn.id,
    );
    if (!splitDone.ok) {
      console.error('consumePaymentRecorded pos_card_tender', reference, posSaleId, splitDone.error);
      return { ok: false, error: splitDone.error ?? 'pos_card_tender_failed' };
    }

    await emitMerchantBusinessEvent(admin, {
      merchantId,
      eventType: 'pos_card_settled',
      actorType: 'system',
      customerEmail: txn.buyer_email ?? null,
      reference,
      amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
      currency: ctx.currency ?? txn.currency ?? null,
      source: 'payment.recorded',
      idempotencyKey: `pos_card_settled:${reference}`,
      payload: {
        pos_sale_id: posSaleId,
        business_intent: businessIntent,
        capture_method: captureMethod,
        processing_rail: ctx.processingRail ?? null,
        txn_key: ctx.txnKey ?? null,
        transaction_id: txn.id,
      },
    });
  }

  const checkoutMeta = await resolveCheckoutMetadata(admin, {
    reference,
    paymentSessionId: txn.payment_session_id,
    sessionMeta,
  });

  if (!shouldSkipInventoryForPayment(checkoutMeta)) {
    const inv = await requestAndConsumeInventory(admin, {
      reference,
      merchantId,
      transactionId: txn.id,
      buyerEmail: txn.buyer_email,
      amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
      currency: ctx.currency ?? txn.currency ?? null,
      paymentSessionId: txn.payment_session_id,
      metadata: checkoutMeta,
      correlationId: ctx.correlationId ?? null,
      causationId: ctx.causationId ?? null,
    });
    if (!inv.ok) {
      console.error('consumePaymentRecorded inventory', reference, inv.reason);
    }
  }

  await consumeCrmFromPaymentRecorded(admin, {
    reference,
    merchantId,
    transactionId: txn.id,
    buyerEmail: txn.buyer_email,
    amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
    currency: ctx.currency ?? txn.currency ?? null,
    paymentSessionId: txn.payment_session_id,
    businessIntent: businessIntent ?? ctx.businessIntent ?? null,
    processingRail: ctx.processingRail ?? null,
    correlationId: ctx.correlationId ?? null,
    causationId: ctx.causationId ?? null,
  });

  // Multi-vendor marketplace loyalty stays in fan-out (per seller subtotal).
  if (!isMarketplaceCheckout(checkoutMeta)) {
    await consumeLoyaltyFromPaymentRecorded(admin, {
      reference,
      merchantId,
      buyerEmail: txn.buyer_email,
      amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
      currency: ctx.currency ?? txn.currency ?? null,
      paymentSessionId: txn.payment_session_id,
    });
  }

  const purchaseType = String(
    checkoutMeta.purchase_type ?? checkoutMeta.object_type ?? '',
  ).toLowerCase();
  await consumeReviewLifecycleFromPaymentRecorded(admin, {
    reference,
    merchantId,
    buyerEmail: txn.buyer_email,
    amount: Number(ctx.amount ?? txn.amount ?? 0) || null,
    currency: ctx.currency ?? txn.currency ?? null,
    purchaseType,
    correlationId: ctx.correlationId ?? null,
    causationId: ctx.causationId ?? null,
  });

  return { ok: true };
}

/**
 * Business Fact Envelope — shared shape for every kernel-emitted fact.
 *
 * correlation_id ties together one business operation (e.g. a checkout).
 * causation_id names the immediate parent fact that caused this one.
 *
 * @see docs/codex/platform/commerce-language-specification.md
 */

export type BusinessFactEnvelope = {
  id: string;
  type: string;
  version: number;
  occurred_at: string;
  producer: string;
  correlation_id: string;
  causation_id: string | null;
  merchant_id: string | null;
  reference: string | null;
  payload: Record<string, unknown>;
};

export type CreateEnvelopeOpts = {
  type: string;
  producer?: string;
  merchantId?: string | null;
  reference?: string | null;
  correlationId?: string | null;
  causationId?: string | null;
  version?: number;
  payload?: Record<string, unknown>;
  /** Stable id for idempotent emission; defaults to a new UUID. */
  id?: string | null;
};

export function correlationIdForPayment(reference: string): string {
  return `corr_pay_${String(reference).replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 80)}`;
}

export function createBusinessFactEnvelope(opts: CreateEnvelopeOpts): BusinessFactEnvelope {
  const reference = opts.reference ? String(opts.reference) : null;
  const correlation =
    String(opts.correlationId ?? '').trim()
    || (reference ? correlationIdForPayment(reference) : `corr_${crypto.randomUUID().replace(/-/g, '')}`);

  return {
    id: String(opts.id ?? '').trim() || crypto.randomUUID(),
    type: opts.type,
    version: opts.version ?? 1,
    occurred_at: new Date().toISOString(),
    producer: opts.producer ?? 'commerce-kernel',
    correlation_id: correlation,
    causation_id: opts.causationId ? String(opts.causationId) : null,
    merchant_id: opts.merchantId ?? null,
    reference,
    payload: opts.payload ?? {},
  };
}

/** Flatten envelope metadata into a payload object for legacy RPC callers. */
export function envelopeIntoPayload(envelope: BusinessFactEnvelope): Record<string, unknown> {
  return {
    ...envelope.payload,
    _envelope: {
      id: envelope.id,
      type: envelope.type,
      version: envelope.version,
      occurred_at: envelope.occurred_at,
      producer: envelope.producer,
      correlation_id: envelope.correlation_id,
      causation_id: envelope.causation_id,
    },
  };
}

/**
 * Payment Terminal abstraction — SoftPOS-ready.
 *
 * Doctrine: the UI must never know whether the merchant is using an NFC card,
 * SoftPOS phone, QR, payment link, or external reader. Every payment source
 * implements the same terminal contract. SoftPOS partners plug in by registering
 * a rail + flipping terminal.provider — business modules stay unchanged.
 *
 * @see docs/codex/platform/financial-abstraction-layer.md
 * @see docs/codex/platform/commerce-intelligence-engine-doctrine.md
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import type { CaptureMethod } from './paymentRouting.ts';

export type TerminalKind =
  | 'nfc_card'
  | 'softpos'
  | 'qr'
  | 'payment_link'
  | 'cash'
  | 'external_reader';

export type TerminalStatus = 'active' | 'inactive' | 'pending_onboarding';

/**
 * First-class payment terminal. NFC cards (payment_objects) are one kind;
 * SoftPOS phones, QR posters, and payment links are others.
 */
export type PaymentTerminal = {
  id: string;
  kind: TerminalKind;
  label: string;
  status: TerminalStatus;
  merchantId: string;
  /** Capture method this terminal asks the Routing Engine to settle. */
  captureMethod: CaptureMethod;
  /** SoftPOS / acquiring partner when kind requires one. */
  provider: string | null;
  tapCode: string | null;
  locationId: string | null;
  deviceRef: string | null;
  supportedMethods: string[];
  capabilities: string[];
};

export type PaymentObjectRow = {
  id: string;
  merchant_id: string;
  label: string | null;
  tap_code: string | null;
  medium: string | null;
  status: string | null;
  type: string | null;
  metadata?: Record<string, unknown> | null;
};

function metaString(meta: Record<string, unknown> | null | undefined, key: string): string | null {
  const v = meta?.[key];
  if (v == null) return null;
  const s = String(v).trim();
  return s || null;
}

/**
 * Map a payment_object row → PaymentTerminal.
 * SoftPOS objects carry metadata.terminal_kind = 'softpos' + metadata.provider.
 */
export function paymentObjectToTerminal(row: PaymentObjectRow): PaymentTerminal {
  const meta = row.metadata && typeof row.metadata === 'object' ? row.metadata : {};
  const kindRaw = metaString(meta, 'terminal_kind') ?? metaString(meta, 'kind');
  const medium = String(row.medium ?? '').toLowerCase();
  const provider = metaString(meta, 'provider') ?? metaString(meta, 'softpos_partner');

  let kind: TerminalKind = 'nfc_card';
  if (kindRaw === 'softpos' || medium === 'softpos') kind = 'softpos';
  else if (kindRaw === 'qr' || medium === 'qr') kind = 'qr';
  else if (kindRaw === 'external_reader' || medium === 'reader') kind = 'external_reader';
  else if (row.tap_code || medium === 'nfc' || medium === 'tag') kind = 'nfc_card';

  const captureMethod: CaptureMethod =
    kind === 'softpos'
      ? (provider === 'istore_tap' ? 'apple_tap' : 'softpos')
      : kind === 'qr'
        ? 'qr'
        : kind === 'external_reader'
          ? 'external_terminal'
          : 'nfc_tap';

  const status: TerminalStatus =
    row.status === 'active'
      ? (kind === 'softpos' && !provider ? 'pending_onboarding' : 'active')
      : row.status === 'pending'
        ? 'pending_onboarding'
        : 'inactive';

  return {
    id: String(row.id),
    kind,
    label: String(row.label ?? (kind === 'softpos' ? 'SoftPOS' : 'Terminal')),
    status,
    merchantId: String(row.merchant_id),
    captureMethod,
    provider,
    tapCode: row.tap_code ? String(row.tap_code) : null,
    locationId: metaString(meta, 'location_id'),
    deviceRef: metaString(meta, 'device_ref') ?? metaString(meta, 'device'),
    supportedMethods: kind === 'cash'
      ? ['cash']
      : kind === 'softpos'
        ? ['softpos', 'apple_tap', 'card_present']
        : ['nfc_tap', 'qr', 'payment_link'],
    capabilities: [
      'collect_payment',
      ...(kind === 'nfc_card' || kind === 'softpos' ? ['pos_terminal'] : []),
      ...(kind === 'softpos' ? ['softpos'] : []),
    ],
  };
}

/** Synthetic terminals that are not payment_objects (cash drawer, pay-by-link). */
export function syntheticTerminals(merchantId: string): PaymentTerminal[] {
  return [
    {
      id: `synthetic:cash:${merchantId}`,
      kind: 'cash',
      label: 'Cash',
      status: 'active',
      merchantId,
      captureMethod: 'cash',
      provider: null,
      tapCode: null,
      locationId: null,
      deviceRef: null,
      supportedMethods: ['cash'],
      capabilities: ['collect_payment', 'cash_register'],
    },
    {
      id: `synthetic:link:${merchantId}`,
      kind: 'payment_link',
      label: 'Payment link',
      status: 'active',
      merchantId,
      captureMethod: 'payment_link',
      provider: null,
      tapCode: null,
      locationId: null,
      deviceRef: null,
      supportedMethods: ['payment_link'],
      capabilities: ['collect_payment', 'share_link'],
    },
  ];
}

export async function listPaymentTerminals(
  admin: SupabaseClient,
  merchantId: string,
  opts?: { includeSynthetic?: boolean },
): Promise<PaymentTerminal[]> {
  let data: PaymentObjectRow[] | null = null;

  const withMeta = await admin
    .from('payment_objects')
    .select('id, merchant_id, label, tap_code, medium, status, type, metadata')
    .eq('merchant_id', merchantId)
    .eq('status', 'active')
    .order('created_at', { ascending: true })
    .limit(100);

  if (!withMeta.error) {
    data = (withMeta.data ?? []) as PaymentObjectRow[];
  } else {
    // metadata column may not exist until migration 0270
    const fallback = await admin
      .from('payment_objects')
      .select('id, merchant_id, label, tap_code, medium, status, type')
      .eq('merchant_id', merchantId)
      .eq('status', 'active')
      .order('created_at', { ascending: true })
      .limit(100);
    if (fallback.error) {
      return opts?.includeSynthetic === false ? [] : syntheticTerminals(merchantId);
    }
    data = (fallback.data ?? []) as PaymentObjectRow[];
  }

  const fromObjects = data.map((row) => paymentObjectToTerminal(row));

  if (opts?.includeSynthetic === false) return fromObjects;
  return [...fromObjects, ...syntheticTerminals(merchantId)];
}

export async function getPaymentTerminal(
  admin: SupabaseClient,
  merchantId: string,
  terminalId: string,
): Promise<PaymentTerminal | null> {
  if (terminalId.startsWith('synthetic:')) {
    return syntheticTerminals(merchantId).find((t) => t.id === terminalId) ?? null;
  }
  const { data } = await admin
    .from('payment_objects')
    .select('id, merchant_id, label, tap_code, medium, status, type, metadata')
    .eq('id', terminalId)
    .eq('merchant_id', merchantId)
    .maybeSingle();
  if (!data) return null;
  return paymentObjectToTerminal(data as PaymentObjectRow);
}

/** Capture method the Routing Engine should use for this terminal. */
export function terminalCaptureMethod(terminal: PaymentTerminal): CaptureMethod {
  return terminal.captureMethod;
}

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export type LineItemInput = {
  product_id?: string | null;
  name: string;
  quantity: number;
  unit_price: number;
  discount?: number;
  tax_amount?: number;
  line_total?: number;
  variant_label?: string | null;
  meta?: Record<string, unknown>;
};

function parseCartJson(json: string | null | undefined): LineItemInput[] {
  if (!json) return [];
  try {
    const parsed = JSON.parse(json);
    if (!Array.isArray(parsed)) return [];
      return parsed.map((row, idx) => {
      const qty = Math.max(1, Number(row.quantity) || 1);
      const unit = Number(row.price ?? row.unit_price) || 0;
      const lineTotal = Number(row.line_total) || round2(unit * qty);
      return {
        product_id: row.product_id ?? null,
        name: String(row.name ?? 'Item'),
        quantity: qty,
        unit_price: unit,
        discount: Number(row.discount) || 0,
        tax_amount: Number(row.tax_amount) || 0,
        line_total: lineTotal,
        variant_label: row.variant_label ?? null,
        meta: {
          sort_order: idx,
          variant_id: row.variant_id ?? null,
          ...(row.category ? { category: String(row.category) } : {}),
          ...(row.category_id ? { category_id: String(row.category_id) } : {}),
          ...(typeof row.meta === 'object' ? row.meta : {}),
        },
      };
    }).filter((l) => l.name);
  } catch {
    return [];
  }
}

function round2(n: number) {
  return Math.round(n * 100) / 100;
}

function linesFromSessionCartItems(cartItems: unknown): LineItemInput[] {
  if (!Array.isArray(cartItems) || cartItems.length === 0) return [];
  return cartItems.map((row, idx) => {
    const item = row as Record<string, unknown>;
    const qty = Math.max(1, Number(item.quantity ?? item.qty) || 1);
    const unit = Number(item.price ?? item.unit_price) || 0;
    return {
      product_id: item.product_id ? String(item.product_id) : null,
      name: String(item.name ?? 'Item'),
      quantity: qty,
      unit_price: unit,
      line_total: round2(Number(item.line_total) || unit * qty),
      variant_label: item.variant_label ? String(item.variant_label) : null,
      meta: {
        sort_order: idx,
        variant_id: item.variant_id ?? null,
        ...(item.category ? { category: String(item.category) } : {}),
        ...(item.category_id ? { category_id: String(item.category_id) } : {}),
        ...(typeof item.meta === 'object' && item.meta ? item.meta as Record<string, unknown> : {}),
      },
    };
  }).filter((l) => l.name);
}

/** Multi-vendor marketplace checkout (same inventory pipeline as standard cart). */
export function isMarketplaceCheckout(metadata: Record<string, unknown>): boolean {
  return String(metadata.object_type ?? '') === 'marketplace_cart'
    || metadata.marketplace_checkout === true
    || String(metadata.purchase_type ?? '') === 'marketplace_cart';
}

export function shouldSkipInventoryForPayment(metadata: Record<string, unknown>): boolean {
  // POS already deducted stock in record_pos_*_sale.
  if (String(metadata.pos_sale_id ?? '').trim()) return true;
  const purchaseType = String(metadata.purchase_type ?? '');
  if (
    purchaseType
    && purchaseType !== 'cart'
    && purchaseType !== 'product'
    && purchaseType !== 'marketplace_cart'
  ) {
    return true;
  }
  return false;
}

/** Resolve checkout metadata without provider APIs (session + platform spine). */
export async function resolveCheckoutMetadata(
  admin: SupabaseClient,
  input: {
    reference: string;
    paymentSessionId?: string | null;
    sessionMeta?: Record<string, unknown>;
  },
): Promise<Record<string, unknown>> {
  const meta: Record<string, unknown> = {
    ...(input.sessionMeta && typeof input.sessionMeta === 'object' ? input.sessionMeta : {}),
  };

  if (input.paymentSessionId) {
    const { data: sess } = await admin
      .from('payment_sessions')
      .select('metadata, cart_items')
      .eq('id', input.paymentSessionId)
      .maybeSingle();
    if (sess) {
      if (sess.metadata && typeof sess.metadata === 'object') {
        Object.assign(meta, sess.metadata as Record<string, unknown>);
      }
      const fromCart = linesFromSessionCartItems(sess.cart_items);
      if (fromCart.length && !meta.cart_items_json) {
        meta.cart_items_json = JSON.stringify(fromCart.map((l) => ({
          product_id: l.product_id,
          name: l.name,
          quantity: l.quantity,
          price: l.unit_price,
          line_total: l.line_total,
          variant_id: l.meta?.variant_id ?? null,
        })));
      }
    }
  }

  const { data: created } = await admin
    .from('platform_payment_events')
    .select('payload')
    .eq('paystack_reference', input.reference)
    .eq('event_type', 'payment.created')
    .order('created_at', { ascending: false })
    .limit(1)
    .maybeSingle();
  if (created?.payload && typeof created.payload === 'object') {
    Object.assign(meta, created.payload as Record<string, unknown>);
  }

  const { data: webhook } = await admin
    .from('platform_webhook_events')
    .select('payload')
    .eq('paystack_reference', input.reference)
    .eq('event_type', 'charge.success')
    .order('processed_at', { ascending: false })
    .limit(1)
    .maybeSingle();
  const whPayload = webhook?.payload as Record<string, unknown> | undefined;
  const paystackMeta = (whPayload?.data as Record<string, unknown> | undefined)?.metadata;
  if (paystackMeta && typeof paystackMeta === 'object') {
    Object.assign(meta, paystackMeta as Record<string, unknown>);
  }

  return meta;
}

export async function applyInventoryForRecordedPayment(
  admin: SupabaseClient,
  input: {
    reference: string;
    transactionId: string;
    metadata: Record<string, unknown>;
  },
): Promise<{ applied: boolean; skipped?: boolean; reason?: string }> {
  if (shouldSkipInventoryForPayment(input.metadata)) {
    return { applied: false, skipped: true, reason: 'inventory_not_applicable' };
  }

  const { count } = await admin
    .from('stock_movements')
    .select('id', { count: 'exact', head: true })
    .eq('reason', `sale:${input.reference}`);
  if ((count ?? 0) > 0) {
    return { applied: false, skipped: true, reason: 'already_applied' };
  }

  const { data, error } = await admin.rpc('apply_inventory_from_transaction', {
    p_transaction_id: input.transactionId,
  });
  if (error) {
    console.error('apply_inventory_from_transaction', input.reference, error.message);
    return { applied: false, skipped: false, reason: error.message };
  }

  const row = (data ?? {}) as { ok?: boolean; skipped?: boolean; lines_applied?: number };
  if (row.skipped) return { applied: false, skipped: true, reason: 'rpc_skipped' };
  return { applied: (row.lines_applied ?? 0) > 0 };
}

/**
 * Flatten multi-vendor marketplace carts onto one parent transaction's line items.
 * Ownership (seller merchant_id) is carried in line meta for stock_movements.
 */
export async function loadMarketplaceLineItems(
  admin: SupabaseClient,
  reference: string,
): Promise<LineItemInput[]> {
  const ref = String(reference ?? '').trim();
  if (!ref) return [];

  const { data: checkout } = await admin
    .from('marketplace_checkouts')
    .select('id')
    .eq('reference', ref)
    .maybeSingle();
  if (!checkout?.id) return [];

  const { data: vendorRows } = await admin
    .from('marketplace_checkout_vendors')
    .select('merchant_id, cart_items_json')
    .eq('marketplace_checkout_id', checkout.id);

  const allLines: LineItemInput[] = [];
  for (const row of vendorRows ?? []) {
    const merchantId = String(row.merchant_id ?? '');
    const items = Array.isArray(row.cart_items_json)
      ? row.cart_items_json as Array<Record<string, unknown>>
      : [];
    for (let idx = 0; idx < items.length; idx++) {
      const item = items[idx];
      const qty = Math.max(1, Number(item.quantity) || 1);
      const unit = Number(item.price ?? item.unit_price) || 0;
      const productId = item.product_id ? String(item.product_id) : null;
      allLines.push({
        product_id: productId,
        name: String(item.name ?? 'Item'),
        quantity: qty,
        unit_price: unit,
        line_total: round2(unit * qty),
        variant_label: item.variant_label ? String(item.variant_label) : null,
        meta: {
          sort_order: allLines.length,
          variant_id: item.variant_id ?? null,
          marketplace_checkout_id: checkout.id,
          merchant_id: merchantId,
        },
      });
    }
  }
  return allLines.filter((l) => l.name);
}

export async function loadTableTabLineItems(
  admin: SupabaseClient,
  paymentSessionId: string | null,
): Promise<LineItemInput[]> {
  if (!paymentSessionId) return [];
  const { data: tab } = await admin
    .from('table_tabs')
    .select('id')
    .eq('payment_session_id', paymentSessionId)
    .in('status', ['ready_to_pay', 'paying', 'paid', 'open'])
    .order('updated_at', { ascending: false })
    .limit(1)
    .maybeSingle();
  if (!tab?.id) return [];

  const { data: items } = await admin
    .from('table_tab_items')
    .select('product_id, product_name, quantity, unit_price, line_total')
    .eq('tab_id', tab.id)
    .order('created_at', { ascending: true });

  return (items ?? []).map((row, idx) => ({
    product_id: row.product_id,
    name: row.product_name,
    quantity: Number(row.quantity) || 1,
    unit_price: Number(row.unit_price) || 0,
    line_total: Number(row.line_total) || 0,
    meta: { source: 'table_tab', tab_id: tab.id, sort_order: idx },
  }));
}

export async function persistTransactionLineItems(
  admin: SupabaseClient,
  input: {
    transactionId: string;
    reference: string;
    lines: LineItemInput[];
    tableTabId?: string | null;
  },
): Promise<void> {
  if (!input.lines.length) return;

  const { count } = await admin
    .from('transaction_line_items')
    .select('id', { count: 'exact', head: true })
    .eq('transaction_id', input.transactionId);
  if ((count ?? 0) > 0) return;

  const subtotal = round2(input.lines.reduce((s, l) => s + (l.line_total ?? l.unit_price * l.quantity), 0));
  const taxTotal = round2(input.lines.reduce((s, l) => s + (l.tax_amount ?? 0), 0));

  const rows = input.lines.map((l, idx) => ({
    transaction_id: input.transactionId,
    product_id: l.product_id ?? null,
    name: l.name,
    quantity: l.quantity,
    unit_price: l.unit_price,
    discount: l.discount ?? 0,
    tax_amount: l.tax_amount ?? 0,
    line_total: l.line_total ?? round2(l.unit_price * l.quantity),
    variant_label: l.variant_label ?? null,
    sort_order: idx,
    meta: l.meta ?? {},
  }));

  await admin.from('transaction_line_items').insert(rows);
  await admin.from('transactions').update({
    subtotal,
    tax_total: taxTotal,
    ...(input.tableTabId ? { table_tab_id: input.tableTabId } : {}),
  }).eq('id', input.transactionId);
}

export async function finalizePaymentLineItems(
  admin: SupabaseClient,
  input: {
    reference: string;
    metadata?: Record<string, unknown> | null;
    paymentSessionId?: string | null;
    /** When false, only persist line items (inventory handled by payment.recorded consumer). */
    applyInventory?: boolean;
  },
): Promise<void> {
  const { data: txn } = await admin
    .from('transactions')
    .select('id, payment_session_id')
    .eq('reference', input.reference)
    .maybeSingle();
  if (!txn?.id) return;

  let lines: LineItemInput[] = [];
  const meta = input.metadata ?? {};

  // Marketplace: load from vendor carts (independent of fan-out order).
  if (isMarketplaceCheckout(meta)) {
    lines = await loadMarketplaceLineItems(admin, input.reference);
  }

  const cartJson = String(meta.cart_items_json ?? '');
  if (!lines.length && cartJson) {
    lines = parseCartJson(cartJson);
  } else if (!lines.length && meta.product_id && meta.label) {
    const qty = Math.max(1, Number(meta.quantity) || 1);
    const unit = Number(meta.unit_price ?? meta.amount) || 0;
    lines = [{
      product_id: String(meta.product_id),
      name: String(meta.label),
      quantity: qty,
      unit_price: unit,
      line_total: round2(unit * qty),
    }];
  }

  const sessionId = input.paymentSessionId ?? txn.payment_session_id ?? null;
  let sessionLabel = '';
  if (!lines.length && sessionId) {
    const { data: sess } = await admin
      .from('payment_sessions')
      .select('cart_items, label, metadata')
      .eq('id', sessionId)
      .maybeSingle();
    if (sess?.cart_items) {
      lines = linesFromSessionCartItems(sess.cart_items);
    }
    const metaNotes = sess?.metadata && typeof sess.metadata === 'object'
      ? String((sess.metadata as Record<string, unknown>).notes ?? '').trim()
      : '';
    sessionLabel = String(sess?.label ?? '').trim() || metaNotes;
  }
  if (!lines.length && sessionId) {
    lines = await loadTableTabLineItems(admin, sessionId);
  }
  // Fallback when flags missing but checkout row exists (replay / older sessions).
  if (!lines.length) {
    lines = await loadMarketplaceLineItems(admin, input.reference);
  }

  // Get Paid free-text: session label / notes is what was sold (e.g. "2x apples").
  if (!lines.length) {
    const { data: txnAmount } = await admin
      .from('transactions')
      .select('amount')
      .eq('id', txn.id)
      .maybeSingle();
    const amount = Number(txnAmount?.amount) || 0;
    let soldAs = sessionLabel;
    if (!soldAs) {
      const { data: order } = await admin
        .from('buyer_orders')
        .select('product_name')
        .eq('transaction_id', txn.id)
        .maybeSingle();
      soldAs = String(order?.product_name ?? '').trim();
    }
    if (!soldAs) {
      soldAs = String(meta.label ?? meta.notes ?? '').trim();
    }
    if (soldAs && amount > 0) {
      lines = [{
        name: soldAs,
        quantity: 1,
        unit_price: amount,
        line_total: round2(amount),
        meta: { source: 'payment_description' },
      }];
    }
  }

  if (!lines.length) return;

  let tableTabId: string | null = null;
  if (sessionId) {
    const { data: tab } = await admin
      .from('table_tabs')
      .select('id')
      .eq('payment_session_id', sessionId)
      .limit(1)
      .maybeSingle();
    tableTabId = tab?.id ?? null;
  }

  await persistTransactionLineItems(admin, {
    transactionId: txn.id,
    reference: input.reference,
    lines,
    tableTabId,
  });

  if (input.applyInventory === false) return;

  // Split POS already deducted stock in record_pos_*_sale — skip second decrement.
  if (shouldSkipInventoryForPayment(meta)) return;

  await applyInventoryForRecordedPayment(admin, {
    reference: input.reference,
    transactionId: txn.id,
    metadata: meta,
  });
}

