/**
 * SoftPOS country / entitlement gate.
 *
 * A Swiss Stripe platform account does NOT imply SoftPOS in South Africa.
 * Availability follows Stripe Terminal Tap to Pay country lists + merchant
 * operating country (Terminal Location), plus explicit entitlement.
 *
 * Sources (GA, not preview): Stripe Tap to Pay docs — iOS + Android.
 * Update when Stripe expands markets; do not invent ZA support.
 */

/** Countries where Stripe Tap to Pay is generally available (union iOS + Android GA). */
export const STRIPE_TERMINAL_TTP_COUNTRIES = new Set([
  'AT',
  'AU',
  'BE',
  'CA',
  'CH',
  'CZ',
  'DE',
  'DK',
  'ES',
  'FI',
  'FR',
  'GB',
  'IE',
  'IT',
  'MY',
  'NL',
  'NZ',
  'PL',
  'PT',
  'SE',
  'SG',
  'US',
]);

export function normalizeSoftposCountry(country?: string | null): string {
  return String(country ?? '').trim().toUpperCase() || 'ZA';
}

/** Stripe Terminal Tap to Pay may be offered only in these operating countries. */
export function isStripeTerminalTtpCountry(country?: string | null): boolean {
  return STRIPE_TERMINAL_TTP_COUNTRIES.has(normalizeSoftposCountry(country));
}

/**
 * SoftPOS offered to the merchant UI / routing.
 * ZA SoftPOS requires a local partner entitlement — never Stripe TTP by default.
 */
export function resolveSoftposOffer(ctx: {
  country?: string | null;
  stripeTerminalEntitled?: boolean;
  saPartner?: 'istore_tap' | 'yoco_tap' | null;
  allowSimulator?: boolean;
}): {
  offered: boolean;
  providerId: 'stripe_terminal' | 'istore_tap' | 'yoco_tap' | 'simulator' | null;
  reason: string;
} {
  const country = normalizeSoftposCountry(ctx.country);

  if (ctx.allowSimulator && Deno.env.get('SOFTPOS_SIMULATOR') === '1') {
    return { offered: true, providerId: 'simulator', reason: 'SOFTPOS_SIMULATOR=1' };
  }

  if (ctx.saPartner === 'istore_tap' && country === 'ZA') {
    return { offered: true, providerId: 'istore_tap', reason: 'ZA SoftPOS via iStore entitlement' };
  }
  if (ctx.saPartner === 'yoco_tap' && country === 'ZA') {
    return { offered: true, providerId: 'yoco_tap', reason: 'ZA SoftPOS via Yoco entitlement' };
  }

  // Stripe TTP: requires Terminal-supported operating country AND entitlement.
  // Env SOFTPOS_STRIPE_ENABLED=1 unlocks after Stripe confirms the business case.
  const stripeEnabled = Deno.env.get('SOFTPOS_STRIPE_ENABLED') === '1';
  if (
    stripeEnabled &&
    ctx.stripeTerminalEntitled &&
    isStripeTerminalTtpCountry(country)
  ) {
    return {
      offered: true,
      providerId: 'stripe_terminal',
      reason: `Stripe Terminal Tap to Pay for ${country}`,
    };
  }

  if (country === 'ZA') {
    return {
      offered: false,
      providerId: null,
      reason:
        'SoftPOS not live in ZA via Stripe Terminal; awaiting SA SoftPOS partner or Stripe confirmation',
    };
  }

  if (isStripeTerminalTtpCountry(country) && !stripeEnabled) {
    return {
      offered: false,
      providerId: null,
      reason: 'Stripe Terminal country, but SoftPOS gated until SOFTPOS_STRIPE_ENABLED=1 and entitlement',
    };
  }

  return {
    offered: false,
    providerId: null,
    reason: `SoftPOS not available for operating country ${country}`,
  };
}

/** Reconcile POS split sales when the card portion clears via Paystack. */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

export async function completePosSplitCardTender(
  admin: SupabaseClient,
  saleId: string,
  reference: string,
  transactionId?: string | null,
): Promise<{ ok: boolean; error?: string }> {
  const id = String(saleId ?? '').trim();
  if (!id) return { ok: false, error: 'sale_id_required' };

  const { data, error } = await admin.rpc('complete_pos_split_card_tender', {
    p_sale_id: id,
    p_reference: reference,
    p_transaction_id: transactionId ?? null,
  });

  if (error) return { ok: false, error: error.message };
  const row = (data ?? {}) as { ok?: boolean; error?: string };
  if (!row.ok) return { ok: false, error: row.error ?? 'complete_failed' };
  return { ok: true };
}

export function posSaleIdFromMetadata(metadata: Record<string, unknown>): string | null {
  const id = String(metadata.pos_sale_id ?? '').trim();
  return id.length >= 32 ? id : null;
}

/**
 * Inventory bounded context — consumes inventory.consume.requested.
 *
 * payment.recorded does not mutate stock directly. It requests consume;
 * this consumer claims, applies stock, and emits inventory.consumed.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';
import {
  finalizePaymentLineItems,
  isMarketplaceCheckout,
  shouldSkipInventoryForPayment,
} from './transactionLineItems.ts';

export type InventoryConsumeInput = {
  reference: string;
  merchantId: string;
  transactionId: string;
  buyerEmail?: string | null;
  amount?: number | null;
  currency?: string | null;
  paymentSessionId?: string | null;
  metadata: Record<string, unknown>;
  correlationId?: string | null;
  causationId?: string | null;
};

export async function consumeInventoryConsumeRequested(
  admin: SupabaseClient,
  input: InventoryConsumeInput,
): Promise<{ ok: boolean; skipped?: boolean; reason?: string; linesApplied?: number }> {
  const reference = String(input.reference ?? '').trim();
  if (!reference || !input.merchantId) {
    return { ok: false, reason: 'reference_and_merchant_required' };
  }

  if (shouldSkipInventoryForPayment(input.metadata)) {
    return { ok: true, skipped: true, reason: 'inventory_not_applicable' };
  }

  const marketplace = isMarketplaceCheckout(input.metadata);
  const { data: claim, error: claimErr } = await admin.rpc('claim_inventory_consume', {
    p_reference: reference,
    p_merchant_id: input.merchantId,
    p_transaction_id: input.transactionId,
    p_marketplace: marketplace,
  });
  if (claimErr) {
    console.error('claim_inventory_consume', reference, claimErr.message);
    return { ok: false, reason: claimErr.message };
  }
  const claimRow = (claim ?? {}) as { ok?: boolean; claimed?: boolean; skipped?: boolean };
  if (claimRow.skipped || claimRow.claimed === false) {
    return { ok: true, skipped: true, reason: 'already_claimed' };
  }

  await finalizePaymentLineItems(admin, {
    reference,
    metadata: input.metadata,
    paymentSessionId: input.paymentSessionId ?? null,
    applyInventory: true,
  });

  const { count: movementCount } = await admin
    .from('stock_movements')
    .select('id', { count: 'exact', head: true })
    .eq('reason', `sale:${reference}`);
  const linesApplied = movementCount ?? 0;

  await admin.rpc('complete_inventory_consume_claim', {
    p_reference: reference,
    p_lines_applied: linesApplied,
  });

  if (linesApplied > 0) {
    await emitMerchantBusinessEvent(admin, {
      merchantId: input.merchantId,
      eventType: 'inventory.consumed',
      actorType: 'system',
      customerEmail: input.buyerEmail ?? null,
      reference,
      amount: input.amount ?? null,
      currency: input.currency ?? null,
      source: 'inventory.consume.requested',
      idempotencyKey: `inventory.consumed:${reference}`,
      payload: {
        fact_type: 'inventory.consumed',
        correlation_id: input.correlationId ?? null,
        causation_id: input.causationId ?? null,
        transaction_id: input.transactionId,
        marketplace,
        movements: linesApplied,
        // Underscore form kept in payload for dashboards that still filter inventory_consumed.
        legacy_event_type: 'inventory_consumed',
      },
    });
  }

  return { ok: true, linesApplied };
}

/** Emit request fact, then run Inventory Consumer (sync dispatch until Kernel v2). */
export async function requestAndConsumeInventory(
  admin: SupabaseClient,
  input: InventoryConsumeInput,
): Promise<{ ok: boolean; skipped?: boolean; reason?: string; linesApplied?: number }> {
  if (shouldSkipInventoryForPayment(input.metadata)) {
    return { ok: true, skipped: true, reason: 'inventory_not_applicable' };
  }

  await emitMerchantBusinessEvent(admin, {
    merchantId: input.merchantId,
    eventType: 'inventory.consume.requested',
    actorType: 'system',
    customerEmail: input.buyerEmail ?? null,
    reference: input.reference,
    amount: input.amount ?? null,
    currency: input.currency ?? null,
    source: 'payment.recorded',
    idempotencyKey: `inventory.consume.requested:${input.reference}`,
    payload: {
      fact_type: 'inventory.consume.requested',
      correlation_id: input.correlationId ?? null,
      causation_id: input.causationId ?? null,
      transaction_id: input.transactionId,
      marketplace: isMarketplaceCheckout(input.metadata),
      payment_session_id: input.paymentSessionId ?? null,
    },
  });

  return consumeInventoryConsumeRequested(admin, {
    ...input,
    causationId: input.causationId ?? `inventory.consume.requested:${input.reference}`,
  });
}

/**
 * CRM consumer — projects merchant_customers from payment.recorded.
 *
 * Facts → projection (not transactions trigger). Claims make it idempotent.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';
import { resolveCheckoutMetadata } from './transactionLineItems.ts';

const NON_CRM_PURCHASE_TYPES = new Set([
  'domain',
  'domain_renewal',
  'plan_subscription',
  'product_subscription',
  'developer_api_subscription',
  'sponsored_listing',
  'agency',
  'studio_subscription',
  'bank_transfer',
]);

export async function consumeCrmFromPaymentRecorded(
  admin: SupabaseClient,
  input: {
    reference: string;
    merchantId: string;
    transactionId: string;
    buyerEmail?: string | null;
    amount?: number | null;
    currency?: string | null;
    paymentSessionId?: string | null;
    businessIntent?: string | null;
    processingRail?: string | null;
    correlationId?: string | null;
    causationId?: string | null;
  },
): Promise<{ ok: boolean; skipped?: boolean; reason?: string }> {
  const reference = String(input.reference ?? '').trim();
  const buyerEmail = String(input.buyerEmail ?? '').trim().toLowerCase();
  if (!reference || !buyerEmail) {
    return { ok: true, skipped: true, reason: 'no_buyer_email' };
  }

  const meta = await resolveCheckoutMetadata(admin, {
    reference,
    paymentSessionId: input.paymentSessionId ?? null,
  });
  const purchaseType = String(meta.purchase_type ?? meta.object_type ?? '').toLowerCase();
  if (NON_CRM_PURCHASE_TYPES.has(purchaseType)) {
    return { ok: true, skipped: true, reason: 'non_crm_purchase' };
  }

  // Projection first: merchant_customers is rebuilt from facts, not the trigger.
  const { data: projected, error: projErr } = await admin.rpc(
    'project_merchant_customer_from_payment',
    { p_reference: reference },
  );
  if (projErr) {
    console.error('project_merchant_customer_from_payment', reference, projErr.message);
    return { ok: false, reason: projErr.message };
  }
  const proj = (projected ?? {}) as { ok?: boolean; projected?: boolean; customer_id?: string };

  const { data: lineItems } = await admin
    .from('transaction_line_items')
    .select('product_id, name, quantity, line_total')
    .eq('transaction_id', input.transactionId)
    .order('sort_order');

  const productSummary = (lineItems ?? [])
    .filter((l) => l.product_id)
    .map((l) => ({
      product_id: l.product_id,
      name: l.name,
      quantity: l.quantity,
      line_total: l.line_total,
    }));

  const { count: priorCount } = await admin
    .from('transactions')
    .select('id', { count: 'exact', head: true })
    .eq('merchant_id', input.merchantId)
    .eq('status', 'success')
    .ilike('buyer_email', buyerEmail)
    .neq('id', input.transactionId)
    .gte('created_at', new Date(Date.now() - 365 * 86400000).toISOString());

  const envelopeMeta = {
    correlation_id: input.correlationId ?? null,
    causation_id: input.causationId ?? null,
  };

  await emitMerchantBusinessEvent(admin, {
    merchantId: input.merchantId,
    eventType: 'customer_purchase_recorded',
    actorType: 'buyer',
    customerEmail: buyerEmail,
    reference,
    amount: input.amount ?? null,
    currency: input.currency ?? null,
    source: 'payment.recorded',
    idempotencyKey: `crm:purchase:${reference}`,
    payload: {
      ...envelopeMeta,
      fact_type: 'customer.purchase_recorded',
      transaction_id: input.transactionId,
      customer_id: proj.customer_id ?? null,
      business_intent: input.businessIntent ?? null,
      processing_rail: input.processingRail ?? null,
      product_count: productSummary.length,
      products: productSummary.slice(0, 20),
      prior_purchases_12mo: priorCount ?? 0,
      projection_created: proj.projected === true,
    },
  });

  if ((priorCount ?? 0) > 0) {
    await emitMerchantBusinessEvent(admin, {
      merchantId: input.merchantId,
      eventType: 'customer_returned',
      actorType: 'buyer',
      customerEmail: buyerEmail,
      reference,
      amount: input.amount ?? null,
      currency: input.currency ?? null,
      source: 'payment.recorded',
      idempotencyKey: `crm:returned:${reference}`,
      payload: {
        ...envelopeMeta,
        fact_type: 'customer.returned',
        prior_purchases: priorCount,
        transaction_id: input.transactionId,
      },
    });
  }

  return { ok: true };
}

/**
 * Loyalty consumer — awards points from payment.recorded (idempotent).
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';
import { resolveCheckoutMetadata } from './transactionLineItems.ts';

const NON_LOYALTY_PURCHASE_TYPES = new Set([
  'domain',
  'domain_renewal',
  'plan_subscription',
  'product_subscription',
  'developer_api_subscription',
  'sponsored_listing',
  'agency',
  'studio_subscription',
]);

export async function consumeLoyaltyFromPaymentRecorded(
  admin: SupabaseClient,
  input: {
    reference: string;
    merchantId: string;
    buyerEmail?: string | null;
    amount?: number | null;
    currency?: string | null;
    paymentSessionId?: string | null;
  },
): Promise<{ ok: boolean; skipped?: boolean; reason?: string; points?: number }> {
  const reference = String(input.reference ?? '').trim();
  const buyerEmail = String(input.buyerEmail ?? '').trim().toLowerCase();
  const amount = Number(input.amount ?? 0);
  if (!reference || !buyerEmail || !(amount > 0)) {
    return { ok: true, skipped: true, reason: 'missing_buyer_or_amount' };
  }

  const meta = await resolveCheckoutMetadata(admin, {
    reference,
    paymentSessionId: input.paymentSessionId ?? null,
  });
  const purchaseType = String(meta.purchase_type ?? meta.object_type ?? '').toLowerCase();
  if (NON_LOYALTY_PURCHASE_TYPES.has(purchaseType)) {
    return { ok: true, skipped: true, reason: 'non_loyalty_purchase' };
  }

  const { data, error } = await admin.rpc('award_loyalty_points', {
    p_merchant_id: input.merchantId,
    p_buyer_email: buyerEmail,
    p_amount: amount,
    p_reference: reference,
  });
  if (error) {
    console.error('award_loyalty_points', reference, error.message);
    return { ok: false, reason: error.message };
  }

  const row = (data ?? {}) as { ok?: boolean; awarded?: boolean; points?: number; skipped?: boolean };
  if (row.skipped || row.awarded === false) {
    return { ok: true, skipped: true, reason: 'already_awarded_or_no_program', points: 0 };
  }

  const points = Number(row.points ?? 0);
  if (points > 0) {
    await emitMerchantBusinessEvent(admin, {
      merchantId: input.merchantId,
      eventType: 'loyalty.points_awarded',
      actorType: 'system',
      customerEmail: buyerEmail,
      reference,
      amount,
      currency: input.currency ?? null,
      source: 'payment.recorded',
      idempotencyKey: `loyalty:award:${reference}`,
      payload: { points, transaction_reference: reference },
    });
  }

  return { ok: true, points };
}

/**
 * Review + thank-you lifecycle from payment.recorded.
 * Immediate thank-you email; review invite after 24h via customer_review_requests cron.
 */

import type { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { emitMerchantBusinessEvent } from './businessEvents.ts';

const NON_REVIEW_PURCHASE_TYPES = new Set([
  'domain',
  'domain_renewal',
  'plan_subscription',
  'product_subscription',
  'developer_api_subscription',
  'sponsored_listing',
  'agency',
  'studio_subscription',
  'bank_transfer',
]);

export async function consumeReviewLifecycleFromPaymentRecorded(
  admin: SupabaseClient,
  input: {
    reference: string;
    merchantId: string;
    buyerEmail?: string | null;
    amount?: number | null;
    currency?: string | null;
    purchaseType?: string | null;
    correlationId?: string | null;
    causationId?: string | null;
  },
): Promise<{ ok: boolean; skipped?: boolean; reason?: string }> {
  const reference = String(input.reference ?? '').trim();
  const buyerEmail = String(input.buyerEmail ?? '').trim().toLowerCase();
  if (!reference || !buyerEmail) {
    return { ok: true, skipped: true, reason: 'no_buyer_email' };
  }

  const purchaseType = String(input.purchaseType ?? '').toLowerCase();
  if (purchaseType && NON_REVIEW_PURCHASE_TYPES.has(purchaseType)) {
    return { ok: true, skipped: true, reason: 'non_review_purchase' };
  }

  const { data: merchant } = await admin
    .from('merchants')
    .select('business_name')
    .eq('id', input.merchantId)
    .maybeSingle();
  const merchantName = String(merchant?.business_name || 'your merchant').trim() || 'your merchant';

  const thankYouBody =
    `Hi,\n\n` +
    `Thank you for shopping with ${merchantName}.\n\n` +
    `Your payment has been received successfully. We appreciate your support.\n\n` +
    `If you need help, contact ${merchantName}.\n\n` +
    `Thank you for using RedFace Pay.`;

  await admin.rpc('enqueue_platform_notification', {
    p_channel: 'email',
    p_recipient: buyerEmail,
    p_event_type: 'purchase_thank_you',
    p_body: thankYouBody,
    p_payload: {
      reference,
      merchant_id: input.merchantId,
      amount: input.amount ?? null,
      currency: input.currency ?? null,
    },
    p_subject: `Thank you for your purchase at ${merchantName}`,
    p_merchant_id: input.merchantId,
    p_reference: reference,
  });

  const { data: allowsReview } = await admin.rpc('customer_allows_review_requests', {
    p_merchant_id: input.merchantId,
    p_email: buyerEmail,
  });
  if (allowsReview === false) {
    return { ok: true, skipped: true, reason: 'review_requests_disabled' };
  }

  const { data: created, error } = await admin.rpc('create_review_request_from_payment', {
    p_reference: reference,
  });
  if (error) {
    console.error('create_review_request_from_payment', reference, error.message);
    return { ok: false, reason: error.message };
  }

  const row = (created ?? {}) as {
    ok?: boolean;
    skipped?: boolean;
    reason?: string;
    id?: string;
    public_token?: string;
  };

  if (row.ok && !row.skipped && row.id) {
    await emitMerchantBusinessEvent(admin, {
      merchantId: input.merchantId,
      eventType: 'review_request_queued',
      actorType: 'system',
      customerEmail: buyerEmail,
      reference,
      amount: input.amount ?? null,
      currency: input.currency ?? null,
      source: 'payment.recorded',
      idempotencyKey: `review_request_queued:${reference}`,
      payload: {
        review_request_id: row.id,
        public_token: row.public_token ?? null,
        send_after_hours: 24,
        correlation_id: input.correlationId ?? null,
        causation_id: input.causationId ?? null,
      },
    });
  }

  return { ok: true, skipped: Boolean(row.skipped), reason: row.reason };
}
